//! Deterministic red-label arcade-core scaffold.
//!
//! This is intentionally small: it establishes fixed-point cabinet state,
//! exact translated constants, a frame-step API, and compatibility hook points.
//! Gameplay routines should be moved here from the original assembly one
//! process at a time until this module replaces the old coarse `World`.

use std::sync::OnceLock;

use self::red_label_trace_samples::{
    red_label_long_instruction_crc_sample, red_label_long_instruction_rand_sample,
};
use crate::{
    board::{
        CMOS_RAM_SIZE, CmosRam, MAIN_CPU_RAM_SIZE, MainCpuRam, PALETTE_RAM_SIZE,
        RED_LABEL_CRHSTD_CELL_OFFSET, RED_LABEL_HIGH_SCORE_ENTRIES,
        RED_LABEL_HIGH_SCORE_ENTRY_CELLS, RED_LABEL_HIGH_SCORE_MAX_SCORE, RED_LABEL_THSTAB_START,
        WATCHDOG_RESET_BYTE, cleared_main_cpu_ram, cmos_sram_read_byte, cmos_sram_read_word,
        cmos_sram_write_byte, cmos_sram_write_word, red_label_crom0_ram_test_next_word,
        video_counter_read_value,
    },
    input::{CabinetInput, DefenderInputPorts},
    machine_state::FrameTraceCrcs,
    red_label::{Facing, Fixed16, RandState, defaults, rmax},
    red_label_memory::{
        RedLabelCmosDefault, RedLabelLinkedList, RedLabelRamLayoutEntry, cmos_4bit_cell_value,
        pack_sram_byte, red_label_cmos_defaults, red_label_cmos_layout, red_label_linked_lists,
        red_label_ram_layout, unpack_sram_byte,
    },
    red_label_wave::{RED_LABEL_WDELT_RECORD_COUNT, red_label_wave_table},
    rom::crc32,
    sound::{SoundCommand, SoundCommandLatch},
    video::{
        DEFENDER_VISIBLE_X_START, DEFENDER_VISIBLE_Y_START, RenderedImage,
        render_defender_visible_palette_indices, render_defender_visible_pixel_nibbles,
        render_defender_visible_rgba, williams_screen_byte_offset,
    },
};

