const RED_LABEL_TRACE_POWER_ON_STAR_BLINK_PREVIOUS_SEED_FRAME: u64 = 1259;
const RED_LABEL_TRACE_POWER_ON_STAR_BLINK_PREVIOUS_RAND_STATE: RandState = RandState {
    seed: 0xA2,
    hseed: 0x53,
    lseed: 0x19,
};
const RED_LABEL_TRACE_POWER_ON_INSTRUCTION_ENTRY_OBJECT_SAMPLE_FRAME: u64 = 1174;
const RED_LABEL_TRACE_POWER_ON_INSTRUCTION_ENTRY_OBJECT_CRC32: u32 = 0x8157_5057;
const RED_LABEL_TRACE_POWER_ON_INSTRUCTION_ENTRY_VIDEO_CRC32: u32 = 0x6741_2219;
const RED_LABEL_TRACE_POWER_ON_INSTRUCTION_OBJECT_POSITION_BYTES: [(u16, u8); 7] = [
    (0xA240, 0x78),
    (0xA241, 0xDB),
    (0xA257, 0x20),
    (0xA258, 0x50),
    (0xA26E, 0x76),
    (0xA26F, 0x40),
    (0xA277, 0xA0),
];

const RED_LABEL_TRACE_ZERO_RAND_STATE: RandState = RandState {
    seed: 0,
    hseed: 0,
    lseed: 0,
};
const RED_LABEL_TRACE_INIT20_SOUND_RAND_STATE: RandState = RandState {
    seed: 0xD9,
    hseed: 0xF6,
    lseed: 0xCC,
};
const RED_LABEL_TRACE_INIT20_OBJECT_LIST_RAND_STATE: RandState = RandState {
    seed: 0x3E,
    hseed: 0xB0,
    lseed: 0x13,
};
const RED_LABEL_TRACE_EXEC_IDLE_RAND_STATE: RandState = RandState {
    seed: 0x86,
    hseed: 0x74,
    lseed: 0x42,
};

const RED_LABEL_SINIT_OBJECT_CLEAR_TARGETS: [RedLabelPowerUpRamFillTarget; 4] = [
    RedLabelPowerUpRamFillTarget {
        frame: 721,
        target_address: 0xA4AC,
    },
    RedLabelPowerUpRamFillTarget {
        frame: 722,
        target_address: 0xA7A0,
    },
    RedLabelPowerUpRamFillTarget {
        frame: 723,
        target_address: 0xAA94,
    },
    RedLabelPowerUpRamFillTarget {
        frame: 724,
        target_address: 0xAD89,
    },
];

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RedLabelPowerOnStage {
    ResetHold,
    RamTestFirstPass,
    RamTestBetweenPasses,
    RamTestSecondPass,
    RamTestComplete,
    SinitZeroSeed,
    SinitClearPlayer,
    SinitClearObjects,
    SinitClearComplete,
    Init20Sound,
    Init20ObjectLists,
    ExecIdleSeed,
    StartReady,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RedLabelPowerOnProcessBoundary {
    AttractVector,
    AttractWilliamsPage,
    AttractColorCadence,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct RedLabelPowerOnFrameModel {
    pub frame: u64,
    pub stage: RedLabelPowerOnStage,
    pub ram_fill_target: u16,
    pub sinit_clear_target: Option<u16>,
    pub rand_state: Option<RandState>,
    pub phase: Option<GamePhase>,
    pub sound_command_port_b: Option<u8>,
    pub initializes_process_lists: bool,
    pub initializes_object_lists: bool,
    pub live_io_blocked: bool,
    pub start_ready: bool,
    pub process_boundary: Option<RedLabelPowerOnProcessBoundary>,
}

impl RedLabelPowerUpRamFill {
    fn new() -> Self {
        Self::from_seed(0, 0)
    }

    fn from_seed(a: u8, b: u8) -> Self {
        Self {
            next_address: 0,
            a,
            b,
        }
    }
}

fn red_label_trace_power_up_ram_fill_target(frame: u64) -> u16 {
    match frame {
        0..=2 => 0x0000,
        3..=64 | 68..=74 => red_label_power_up_ram_fill_target_for_frame(
            frame,
            &RED_LABEL_POWER_UP_RAM_FILL_FIRST_PASS_TARGETS,
        ),
        65..=67 => 0x97F7,
        75..=175 => 0xC000,
        176..=237 | 240..=247 => red_label_power_up_ram_fill_target_for_frame(
            frame,
            &RED_LABEL_POWER_UP_RAM_FILL_SECOND_PASS_TARGETS,
        ),
        238..=239 => 0x97F7,
        _ => 0xC000,
    }
}

fn red_label_power_up_ram_fill_target_for_frame(
    frame: u64,
    targets: &[RedLabelPowerUpRamFillTarget],
) -> u16 {
    targets
        .iter()
        .find(|target| target.frame == frame)
        .map(|target| target.target_address)
        .expect("embedded red-label power-up RAM-fill trace target is complete")
}

fn red_label_sinit_object_clear_target(frame: u64) -> Result<u16, String> {
    RED_LABEL_SINIT_OBJECT_CLEAR_TARGETS
        .iter()
        .find(|target| target.frame == frame)
        .map(|target| target.target_address)
        .ok_or_else(|| format!("red-label SINIT object clear frame {frame} is not mapped"))
}

pub fn red_label_power_on_frame_model(frame: u64) -> Result<RedLabelPowerOnFrameModel, String> {
    let mut model = RedLabelPowerOnFrameModel {
        frame,
        stage: match frame {
            0..=2 => RedLabelPowerOnStage::ResetHold,
            3..=74 => RedLabelPowerOnStage::RamTestFirstPass,
            75..=175 => RedLabelPowerOnStage::RamTestBetweenPasses,
            176..=247 => RedLabelPowerOnStage::RamTestSecondPass,
            248..=719 => RedLabelPowerOnStage::RamTestComplete,
            RED_LABEL_TRACE_SINIT_ZERO_SEED_FRAME => RedLabelPowerOnStage::SinitZeroSeed,
            RED_LABEL_TRACE_SINIT_CLEAR_PLAYER_FRAME => RedLabelPowerOnStage::SinitClearPlayer,
            722..=724 => RedLabelPowerOnStage::SinitClearObjects,
            RED_LABEL_TRACE_SINIT_CLEAR_COMPLETE_FRAME..=730 => {
                RedLabelPowerOnStage::SinitClearComplete
            }
            RED_LABEL_TRACE_INIT20_SOUND_FRAME => RedLabelPowerOnStage::Init20Sound,
            RED_LABEL_TRACE_INIT20_OBJECT_LIST_FRAME => RedLabelPowerOnStage::Init20ObjectLists,
            RED_LABEL_TRACE_EXEC_IDLE_SEED_FRAME..=745 => RedLabelPowerOnStage::ExecIdleSeed,
            _ => RedLabelPowerOnStage::StartReady,
        },
        ram_fill_target: red_label_trace_power_up_ram_fill_target(frame),
        sinit_clear_target: None,
        rand_state: None,
        phase: None,
        sound_command_port_b: None,
        initializes_process_lists: false,
        initializes_object_lists: false,
        live_io_blocked: frame <= RED_LABEL_TRACE_POWER_UP_LIVE_IO_HOLDOFF_END_FRAME,
        start_ready: frame >= RED_LABEL_TRACE_EXEC_RAND_FIRST_FRAME,
        process_boundary: match frame {
            733 => Some(RedLabelPowerOnProcessBoundary::AttractVector),
            739 => Some(RedLabelPowerOnProcessBoundary::AttractWilliamsPage),
            746.. => Some(RedLabelPowerOnProcessBoundary::AttractColorCadence),
            _ => None,
        },
    };

    match model.stage {
        RedLabelPowerOnStage::SinitZeroSeed => {
            let layout = red_label_ram_layout()?;
            model.sinit_clear_target = Some(field_range(&layout, "base_page", "LSEED")?.end);
            model.rand_state = Some(RED_LABEL_TRACE_ZERO_RAND_STATE);
            model.phase = Some(GamePhase::Playing);
        }
        RedLabelPowerOnStage::SinitClearPlayer | RedLabelPowerOnStage::SinitClearObjects => {
            model.sinit_clear_target = Some(red_label_sinit_object_clear_target(frame)?);
            model.rand_state = Some(RED_LABEL_TRACE_ZERO_RAND_STATE);
            model.phase = Some(GamePhase::Attract);
        }
        RedLabelPowerOnStage::SinitClearComplete => {
            if frame == RED_LABEL_TRACE_SINIT_CLEAR_COMPLETE_FRAME {
                model.sinit_clear_target = Some(RED_LABEL_TRACE_SINIT_RAM_CLEAR_END);
            }
            model.rand_state = Some(RED_LABEL_TRACE_ZERO_RAND_STATE);
            model.phase = Some(GamePhase::Attract);
        }
        RedLabelPowerOnStage::Init20Sound => {
            model.rand_state = Some(RED_LABEL_TRACE_INIT20_SOUND_RAND_STATE);
            model.phase = Some(GamePhase::Attract);
            model.sound_command_port_b = Some(RED_LABEL_TRACE_INIT20_SOUND_COMMAND_PORT_B);
            model.initializes_process_lists = true;
        }
        RedLabelPowerOnStage::Init20ObjectLists => {
            model.rand_state = Some(RED_LABEL_TRACE_INIT20_OBJECT_LIST_RAND_STATE);
            model.phase = Some(GamePhase::GameOver);
            model.initializes_object_lists = true;
        }
        RedLabelPowerOnStage::ExecIdleSeed => {
            model.rand_state = Some(RED_LABEL_TRACE_EXEC_IDLE_RAND_STATE);
        }
        RedLabelPowerOnStage::ResetHold
        | RedLabelPowerOnStage::RamTestFirstPass
        | RedLabelPowerOnStage::RamTestBetweenPasses
        | RedLabelPowerOnStage::RamTestSecondPass
        | RedLabelPowerOnStage::RamTestComplete
        | RedLabelPowerOnStage::StartReady => {}
    }

    Ok(model)
}

fn table_descriptor<'a>(
    layout: &'a [RedLabelRamLayoutEntry],
    table: &str,
) -> Result<&'a RedLabelRamLayoutEntry, String> {
    layout
        .iter()
        .find(|entry| entry.table == table)
        .ok_or_else(|| format!("red-label RAM layout has no `{table}` table"))
}

fn table_range(
    layout: &[RedLabelRamLayoutEntry],
    table: &str,
) -> Result<std::ops::Range<usize>, String> {
    let table = table_descriptor(layout, table)?;
    let range = table
        .table_range()
        .ok_or_else(|| format!("red-label `{}` table range is invalid", table.table))?;
    let start = usize::from(range.start);
    let end = usize::from(range.end);
    if start > end || end > MAIN_CPU_RAM_SIZE {
        return Err(format!(
            "red-label `{}` table range 0x{:04X}..0x{:04X} is outside main RAM",
            table.table, range.start, range.end
        ));
    }
    Ok(start..end)
}

fn table_entry_range(
    table: &RedLabelRamLayoutEntry,
    entry_index: u16,
) -> Result<std::ops::Range<u16>, String> {
    if entry_index >= table.entries {
        return Err(format!(
            "red-label `{}` table entry {} exceeds {} entries",
            table.table, entry_index, table.entries
        ));
    }

    let start = u32::from(table.base) + u32::from(entry_index) * u32::from(table.entry_size);
    let end = start + u32::from(table.entry_size);
    if end > u32::from(u16::MAX) {
        return Err(format!(
            "red-label `{}` table entry {} range overflows",
            table.table, entry_index
        ));
    }

    Ok(start as u16..end as u16)
}

fn ram_field<'a>(
    layout: &'a [RedLabelRamLayoutEntry],
    table: &str,
    field: &str,
) -> Result<&'a RedLabelRamLayoutEntry, String> {
    layout
        .iter()
        .find(|entry| entry.table == table && entry.field == field)
        .ok_or_else(|| format!("red-label RAM layout has no `{table}.{field}` field"))
}

fn field_range(
    layout: &[RedLabelRamLayoutEntry],
    table: &str,
    field: &str,
) -> Result<std::ops::Range<u16>, String> {
    ram_field(layout, table, field)?
        .field_range_for_entry(0)
        .ok_or_else(|| format!("red-label {table}.{field} range is invalid"))
}

fn star_field_range(
    layout: &[RedLabelRamLayoutEntry],
    entry_index: u16,
    field: &str,
) -> Result<std::ops::Range<u16>, String> {
    ram_field(layout, "star_map", field)?
        .field_range_for_entry(entry_index)
        .ok_or_else(|| format!("red-label star_map.{field} entry {entry_index} is invalid"))
}

fn translated_player_switch_process(
    triggered_bits: u8,
) -> Result<Option<RedLabelSwitchProcess>, String> {
    if triggered_bits == 0 {
        return Ok(None);
    }

    let switch_bit = 1u8 << triggered_bits.trailing_zeros();
    let Some(entry) = red_label_switch_table()?
        .iter()
        .find(|entry| entry.switch_bit == switch_bit)
    else {
        return Ok(None);
    };
    let Some(routine_label) = entry.routine_label.as_deref() else {
        return Ok(None);
    };

    if !matches!(
        routine_label,
        "LFIRE" | "SBOMB" | "REV" | "HYPER" | "ST1" | "ST2"
    ) {
        return Ok(None);
    }

    let process_type = entry
        .process_type
        .ok_or_else(|| format!("red-label SWTAB entry `{}` has no process type", entry.name))?;
    let status_mask = entry
        .status_mask
        .ok_or_else(|| format!("red-label SWTAB entry `{}` has no status mask", entry.name))?;

    Ok(Some(RedLabelSwitchProcess {
        switch_bit,
        routine_address: red_label_routine_address(routine_label)?,
        process_type,
        status_mask,
    }))
}

fn translated_coin_switch_process(
    confirmed_bits: u8,
) -> Result<Option<RedLabelSwitchProcess>, String> {
    let queueable_bits = confirmed_bits & RED_LABEL_COIN_QUEUEABLE_BITS;
    if queueable_bits == 0 {
        return Ok(None);
    }

    let switch_bit = 1u8 << queueable_bits.trailing_zeros();
    let (routine_label, process_type) = match switch_bit {
        0x02 => ("ADVSW", RED_LABEL_SYSTEM_PROCESS_TYPE),
        0x04 => ("RCOIN", RED_LABEL_COIN_PROCESS_TYPE),
        0x08 => ("HSRES", RED_LABEL_SYSTEM_PROCESS_TYPE),
        0x10 => ("LCOIN", RED_LABEL_COIN_PROCESS_TYPE),
        0x20 => ("CCOIN", RED_LABEL_COIN_PROCESS_TYPE),
        _ => return Ok(None),
    };

    Ok(Some(RedLabelSwitchProcess {
        switch_bit,
        routine_address: red_label_routine_address(routine_label)?,
        process_type,
        status_mask: 0,
    }))
}

fn red_label_switch_table() -> Result<&'static [RedLabelSwitchTableEntry], String> {
    static SWITCH_TABLE: OnceLock<Result<Vec<RedLabelSwitchTableEntry>, String>> = OnceLock::new();
    match SWITCH_TABLE.get_or_init(|| parse_switch_table(crate::assets::RED_LABEL_SWITCH_TABLE_TSV))
    {
        Ok(entries) => Ok(entries.as_slice()),
        Err(error) => Err(error.clone()),
    }
}

fn parse_switch_table(text: &'static str) -> Result<Vec<RedLabelSwitchTableEntry>, String> {
    let mut lines = text.lines();
    match lines.next() {
        Some("bit\tname\troutine\tprocess_type\tstatus_mask\tsource") => {}
        _ => return Err(String::from("red-label SWTAB asset header is invalid")),
    }

    let mut entries = Vec::new();
    for (line_index, line) in lines.enumerate() {
        let line_number = line_index + 2;
        if line.trim().is_empty() {
            continue;
        }
        let columns: Vec<&str> = line.split('\t').collect();
        if columns.len() != 6 {
            return Err(format!(
                "red-label SWTAB line {line_number} must have 6 columns"
            ));
        }
        let switch_bit = parse_asset_hex_u8("SWTAB switch bit", columns[0], line_number)?;
        if switch_bit == 0 || !switch_bit.is_power_of_two() {
            return Err(format!(
                "red-label SWTAB switch bit `{}` on line {line_number} must be one bit",
                columns[0]
            ));
        }
        let name = columns[1];
        if name.is_empty() {
            return Err(format!(
                "red-label SWTAB line {line_number} has an empty name"
            ));
        }
        if columns[5].is_empty() {
            return Err(format!(
                "red-label SWTAB line {line_number} has an empty source"
            ));
        }
        if entries
            .iter()
            .any(|entry: &RedLabelSwitchTableEntry| entry.switch_bit == switch_bit)
        {
            return Err(format!(
                "red-label SWTAB line {line_number} duplicates switch bit `{}`",
                columns[0]
            ));
        }

        let routine_label = if columns[2].is_empty() {
            None
        } else {
            Some(String::from(columns[2]))
        };
        let process_type =
            parse_optional_asset_hex_u8("SWTAB process type", columns[3], line_number)?;
        let status_mask =
            parse_optional_asset_hex_u8("SWTAB status mask", columns[4], line_number)?;
        let has_process_fields = process_type.is_some() || status_mask.is_some();
        if routine_label.is_some() && !has_process_fields {
            return Err(format!(
                "red-label SWTAB line {line_number} has a routine but no process fields"
            ));
        }
        if routine_label.is_some() && (process_type.is_none() || status_mask.is_none()) {
            return Err(format!(
                "red-label SWTAB line {line_number} must have both process type and status mask"
            ));
        }
        if routine_label.is_none() && has_process_fields {
            return Err(format!(
                "red-label SWTAB line {line_number} has process fields without a routine"
            ));
        }

        entries.push(RedLabelSwitchTableEntry {
            switch_bit,
            name: String::from(name),
            routine_label,
            process_type,
            status_mask,
        });
    }

    if entries.len() != 8
        || entries
            .iter()
            .fold(0u8, |bits, entry| bits | entry.switch_bit)
            != 0xFF
    {
        return Err(String::from(
            "red-label SWTAB asset must contain exactly the eight IN0 switch bits",
        ));
    }
    Ok(entries)
}

fn process_table_for_address(
    layout: &[RedLabelRamLayoutEntry],
    address: u16,
) -> Result<&RedLabelRamLayoutEntry, String> {
    let process = table_descriptor(layout, "process")?;
    if process
        .table_range()
        .is_some_and(|range| range.contains(&address))
    {
        entry_index_for_address(process, address)?;
        return Ok(process);
    }

    let super_process = table_descriptor(layout, "super_process")?;
    if super_process
        .table_range()
        .is_some_and(|range| range.contains(&address))
    {
        entry_index_for_address(super_process, address)?;
        return Ok(super_process);
    }

    Err(format!(
        "red-label address 0x{address:04X} is outside process tables"
    ))
}

fn process_field_range_for_address(
    layout: &[RedLabelRamLayoutEntry],
    table: &RedLabelRamLayoutEntry,
    address: u16,
    field: &str,
) -> Result<std::ops::Range<u16>, String> {
    let entry_index = entry_index_for_address(table, address)?;
    ram_field(layout, &table.table, field)?
        .field_range_for_entry(entry_index)
        .ok_or_else(|| format!("red-label {}.{field} range is invalid", table.table))
}

fn object_table_for_address(
    layout: &[RedLabelRamLayoutEntry],
    address: u16,
) -> Result<&RedLabelRamLayoutEntry, String> {
    let object = table_descriptor(layout, "object")?;
    if object
        .table_range()
        .is_some_and(|range| range.contains(&address))
    {
        entry_index_for_address(object, address)?;
        return Ok(object);
    }

    Err(format!(
        "red-label address 0x{address:04X} is outside object table"
    ))
}

fn raw_attract_defender_object_contains(address: u16) -> bool {
    let Some(offset) = address.checked_sub(RED_LABEL_ATTRACT_DEFENDER_OBJECTS) else {
        return false;
    };
    offset
        < u16::from(RED_LABEL_ATTRACT_DEFENDER_OBJECT_COUNT)
            * RED_LABEL_ATTRACT_DEFENDER_OBJECT_BYTES
        && offset % RED_LABEL_ATTRACT_DEFENDER_OBJECT_BYTES == 0
}

fn raw_attract_defender_picture_contains(address: u16) -> bool {
    let Some(offset) = address.checked_sub(RED_LABEL_ATTRACT_DEFENDER_PICTURES) else {
        return false;
    };
    offset
        < u16::from(RED_LABEL_ATTRACT_DEFENDER_OBJECT_COUNT)
            * RED_LABEL_ATTRACT_DEFENDER_PICTURE_BYTES
        && offset % RED_LABEL_ATTRACT_DEFENDER_PICTURE_BYTES == 0
}

fn raw_attract_defender_object_field_address(
    object_address: u16,
    field: &str,
) -> Result<u16, String> {
    if !raw_attract_defender_object_contains(object_address) {
        return Err(format!(
            "red-label address 0x{object_address:04X} is outside raw Defender object cells"
        ));
    }

    let offset = match field {
        "OPICT" => RED_LABEL_ATTRACT_DEFENDER_OBJECT_PICTURE_OFFSET,
        "OX16" => RED_LABEL_ATTRACT_DEFENDER_OBJECT_X16_OFFSET,
        "OY16" => RED_LABEL_ATTRACT_DEFENDER_OBJECT_Y16_OFFSET,
        "OTYP" => RED_LABEL_ATTRACT_DEFENDER_OBJECT_TYPE_OFFSET,
        _ => {
            return Err(format!(
                "red-label raw Defender object field {field} is invalid"
            ));
        }
    };
    Ok(object_address.wrapping_add(offset))
}

fn object_field_range_for_address(
    layout: &[RedLabelRamLayoutEntry],
    address: u16,
    field: &str,
) -> Result<std::ops::Range<u16>, String> {
    let object = object_table_for_address(layout, address)?;
    let entry_index = entry_index_for_address(object, address)?;
    ram_field(layout, "object", field)?
        .field_range_for_entry(entry_index)
        .ok_or_else(|| format!("red-label object.{field} range is invalid"))
}

