fn parse_color_ram_tables(text: &'static str) -> Result<Vec<RedLabelColorRamTable>, String> {
    let mut lines = text.lines();
    match lines.next() {
        Some("label\taddress\tbytes\tsource") => {}
        _ => {
            return Err(String::from("red-label color-RAM asset header is invalid"));
        }
    }

    let mut tables = Vec::new();
    for (line_index, line) in lines.enumerate() {
        let line_number = line_index + 2;
        if line.trim().is_empty() {
            continue;
        }
        let columns: Vec<&str> = line.split('\t').collect();
        if columns.len() != 4 {
            return Err(format!(
                "red-label color-RAM line {line_number} must have 4 columns"
            ));
        }
        let label = columns[0];
        if label.is_empty() {
            return Err(format!(
                "red-label color-RAM line {line_number} has an empty label"
            ));
        }
        if columns[3].is_empty() {
            return Err(format!(
                "red-label color-RAM line {line_number} has an empty source"
            ));
        }
        if tables
            .iter()
            .any(|entry: &RedLabelColorRamTable| entry.label == label)
        {
            return Err(format!(
                "red-label color-RAM line {line_number} duplicates label `{label}`"
            ));
        }
        tables.push(RedLabelColorRamTable {
            label: String::from(label),
            address: parse_asset_hex_u16("color-RAM table address", columns[1], line_number)?,
            bytes: parse_hex_pairs("color-RAM bytes", columns[2], line_number)?,
        });
    }

    if tables.is_empty() {
        return Err(String::from("red-label color-RAM asset has no records"));
    }
    Ok(tables)
}

