    match OBJECT_PICTURES
        .get_or_init(|| parse_object_pictures(crate::assets::RED_LABEL_OBJECT_PICTURES_TSV))
    {
        Ok(pictures) => Ok(pictures.as_slice()),
        Err(error) => Err(error.clone()),
    }
