fn parse_object_pictures(text: &'static str) -> Result<Vec<RedLabelObjectPicture>, String> {
    let mut lines = text.lines();
    match lines.next() {
        Some(
            "label\taddress\twidth\theight\tprimary_image\talternate_image\toutput_routine\terase_routine\tsource",
        ) => {}
        _ => {
            return Err(String::from(
                "red-label object picture asset header is invalid",
            ));
        }
    }

    let mut pictures = Vec::new();
    for (line_index, line) in lines.enumerate() {
        let line_number = line_index + 2;
        if line.trim().is_empty() {
            continue;
        }
        let columns: Vec<&str> = line.split('\t').collect();
        if columns.len() != 9 {
            return Err(format!(
                "red-label object picture line {line_number} must have 9 columns"
            ));
        }
        let label = columns[0];
        if label.is_empty() {
            return Err(format!(
                "red-label object picture line {line_number} has an empty label"
            ));
        }
        if columns[8].is_empty() {
            return Err(format!(
                "red-label object picture line {line_number} has an empty source"
            ));
        }
        let alternate_image = parse_optional_asset_hex_u16(
            "object picture alternate image",
            columns[5],
            line_number,
        )?;
        let output_routine =
            parse_optional_asset_hex_u16("object picture output routine", columns[6], line_number)?;
        let erase_routine =
            parse_optional_asset_hex_u16("object picture erase routine", columns[7], line_number)?;
        let has_complete_descriptor =
            alternate_image.is_some() && output_routine.is_some() && erase_routine.is_some();
        let has_partial_descriptor =
            alternate_image.is_some() || output_routine.is_some() || erase_routine.is_some();
        if has_partial_descriptor && !has_complete_descriptor {
            return Err(format!(
                "red-label object picture line {line_number} must have all optional descriptor words or none"
            ));
        }
        pictures.push(RedLabelObjectPicture {
            label: String::from(label),
            address: parse_asset_hex_u16("object picture address", columns[1], line_number)?,
            width: parse_asset_u8("object picture width", columns[2], line_number)?,
            height: parse_asset_u8("object picture height", columns[3], line_number)?,
            primary_image: parse_asset_hex_u16(
                "object picture primary image",
                columns[4],
                line_number,
            )?,
            alternate_image,
            output_routine,
            erase_routine,
        });
    }
    if pictures.is_empty() {
        return Err(String::from(
            "red-label object picture asset has no records",
        ));
    }
    Ok(pictures)
}

fn picture_collision_center(
    candidate_picture: &RedLabelObjectPicture,
    candidate_upper_left: u16,
    object_picture: &RedLabelObjectPicture,
    object_upper_left: u16,
) -> Result<Option<u16>, String> {
    let [candidate_x, candidate_y] = candidate_upper_left.to_be_bytes();
    let [candidate_lr_x, candidate_lr_y] =
        picture_lower_right(candidate_upper_left, candidate_picture);
    let [object_x, object_y] = object_upper_left.to_be_bytes();
    let [object_lr_x, object_lr_y] = picture_lower_right(object_upper_left, object_picture);

    if object_x >= candidate_lr_x
        || object_y >= candidate_lr_y
        || object_lr_x <= candidate_x
        || object_lr_y <= candidate_y
    {
        return Ok(None);
    }

    let left = candidate_x.max(object_x);
    let right = candidate_lr_x.min(object_lr_x);
    let top = candidate_y.max(object_y);
    let bottom = candidate_lr_y.min(object_lr_y);

    for screen_x in left..right {
        let candidate_offset_x = screen_x.wrapping_sub(candidate_x);
        let object_offset_x = screen_x.wrapping_sub(object_x);
        for screen_y in (top..bottom).rev() {
            let candidate_offset_y = screen_y.wrapping_sub(candidate_y);
            let object_offset_y = screen_y.wrapping_sub(object_y);
            let candidate_byte =
                picture_mask_byte(candidate_picture, candidate_offset_x, candidate_offset_y)?;
            if candidate_byte == 0 {
                continue;
            }
            let object_byte = picture_mask_byte(object_picture, object_offset_x, object_offset_y)?;
            if object_byte != 0 {
                return Ok(Some(u16::from_be_bytes([screen_x, screen_y])));
            }
        }
    }

    Ok(None)
}

fn picture_lower_right(upper_left: u16, picture: &RedLabelObjectPicture) -> [u8; 2] {
    upper_left
        .wrapping_add(u16::from_be_bytes([picture.width, picture.height]))
        .to_be_bytes()
}

fn picture_mask_byte(
    picture: &RedLabelObjectPicture,
    x_offset: u8,
    y_offset: u8,
) -> Result<u8, String> {
    if x_offset >= picture.width || y_offset >= picture.height {
        return Err(format!(
            "red-label picture `{}` mask offset {},{} is outside {}x{}",
            picture.label, x_offset, y_offset, picture.width, picture.height
        ));
    }
    let index = u16::from(x_offset) * u16::from(picture.height) + u16::from(y_offset);
    let address = picture.primary_image.wrapping_add(index);
    red_label_object_image_byte(address)?.ok_or_else(|| {
        format!(
            "red-label object image asset has no byte for `{}` at 0x{address:04X}",
            picture.label
        )
    })
}

