fn live_coin_door_switch_outcome(dispatch: &RedLabelProcessDispatch) -> LiveCoinDoorSwitchOutcome {
    match dispatch {
        RedLabelProcessDispatch::CoinProcess(RedLabelCoinProcessStep::Completed {
            coin_credit:
                RedLabelCoinCredit {
                    credits_awarded: 1..,
                    ..
                },
            ..
        }) => LiveCoinDoorSwitchOutcome {
            credit_added: true,
            admin_event: None,
            ..LiveCoinDoorSwitchOutcome::default()
        },
        RedLabelProcessDispatch::AdminSwitch(RedLabelAdminSwitch::HighScoreReset { .. }) => {
            LiveCoinDoorSwitchOutcome {
                credit_added: false,
                admin_event: Some(MachineEvent::HighScoreReset),
                ..LiveCoinDoorSwitchOutcome::default()
            }
        }
        RedLabelProcessDispatch::AdminSwitch(RedLabelAdminSwitch::AdvanceJump {
            target: RedLabelAdvanceSwitchTarget::Diagnostics,
            ..
        }) => LiveCoinDoorSwitchOutcome {
            credit_added: false,
            admin_event: Some(MachineEvent::DiagnosticsSelected),
            ..LiveCoinDoorSwitchOutcome::default()
        },
        RedLabelProcessDispatch::AdminSwitch(RedLabelAdminSwitch::AdvanceJump {
            target: RedLabelAdvanceSwitchTarget::Audits,
            ..
        }) => LiveCoinDoorSwitchOutcome {
            credit_added: false,
            admin_event: Some(MachineEvent::AuditsSelected),
            ..LiveCoinDoorSwitchOutcome::default()
        },
        _ => LiveCoinDoorSwitchOutcome::default(),
    }
}

fn red_label_process_dispatch_started_game(dispatch: &RedLabelProcessDispatch) -> bool {
    matches!(
        dispatch,
        RedLabelProcessDispatch::StartSwitch(start)
            if red_label_start_switch_initialized_game(start)
    )
}

fn red_label_start_switch_initialized_game(start: &RedLabelStartSwitch) -> bool {
    fn initialized(start: &RedLabelStartGame) -> bool {
        matches!(
            start,
            RedLabelStartGame::Updated {
                initialized: Some(_),
                ..
            }
        )
    }

    match start {
        RedLabelStartSwitch::StartedOne { start, .. } => initialized(start),
        RedLabelStartSwitch::StartedTwo {
            first_start,
            second_start,
            ..
        } => initialized(first_start) || initialized(second_start),
        RedLabelStartSwitch::StatusBlocked { .. }
        | RedLabelStartSwitch::InsufficientCredit { .. } => false,
    }
}

