    #[test]
    fn live_attract_idle_progresses_beyond_initial_williams_screen() {
        let mut machine = ArcadeMachine::new();
        let initial_video_crc = machine
            .red_label_visible_video_crc32()
            .expect("initial video CRC is available");
        let presents_address = red_label_routine_address("PRES").expect("PRES address");
        let pres1_address = red_label_routine_address("PRES1").expect("PRES1 address");
        let defend_address = red_label_routine_address("DEFEND").expect("DEFEND address");
        let defens_address = red_label_routine_address("DEFENS").expect("DEFENS address");
        let defender_restore_address = red_label_routine_address("DEF33").expect("DEF33 address");
        let later_attract_routines = [
            presents_address,
            pres1_address,
            defend_address,
            defens_address,
            defender_restore_address,
        ];
        let mut saw_changed_video = false;
        let mut saw_later_attract_process = false;

        for _ in 0..420 {
            let frame = machine.step(CabinetInput::NONE);

            assert_eq!(frame.snapshot.phase, GamePhase::Attract);
            saw_changed_video |= machine
                .red_label_visible_video_crc32()
                .expect("video CRC remains available")
                != initial_video_crc;
            saw_later_attract_process |= machine
                .memory
                .active_process_has_routine(&later_attract_routines)
                .expect("query later attract process");
        }

        assert!(saw_changed_video);
        assert!(saw_later_attract_process);
        assert_eq!(machine.snapshot().credits, 0);

        let credit_output = insert_live_coin(&mut machine);
        assert!(
            credit_output
                .events()
                .any(|event| event == MachineEvent::CreditAdded)
        );
        assert_eq!(credit_output.snapshot.phase, GamePhase::Attract);
        assert!(credit_output.snapshot.credits > 0);

        let mut started_output = None;
        for _ in 0..16 {
            let output = machine.step(CabinetInput {
                start_one: true,
                ..CabinetInput::NONE
            });
            if output
                .events()
                .any(|event| event == MachineEvent::GameStarted)
            {
                started_output = Some(output);
                break;
            }
        }
        let start_output = started_output.expect("credited live attract should start");
        assert_eq!(start_output.snapshot.phase, GamePhase::Playing);
    }

    #[test]
    fn live_attract_idle_advances_past_title_without_corrupting_high_scores() {
        let mut machine = ArcadeMachine::new();
        let todays_end = RED_LABEL_THSTAB_START
            + u16::try_from(RED_LABEL_HIGH_SCORE_ENTRIES * RED_LABEL_HIGH_SCORE_ENTRY_CELLS)
                .expect("today's high-score table length fits in u16");
        let todays_before = machine
            .red_label_ram_range(RED_LABEL_THSTAB_START..todays_end)
            .expect("today's high-score table is available")
            .to_vec();
        let instruction_scene_routines = [
            red_label_routine_address("AMODE1").expect("AMODE1 address"),
            red_label_routine_address("AMODE2").expect("AMODE2 address"),
            red_label_routine_address("TEXTP").expect("TEXTP address"),
            red_label_routine_address("SCPROC").expect("SCPROC address"),
        ];
        let mut title_video_crc = None;
        let mut saw_post_title_video = false;
        let mut saw_instruction_scene_process = false;

        for tick in 1..=6_000 {
            machine
                .step_red_label_live_attract_process()
                .expect("live attract process remains translated");

            if tick == 900 || tick > 900 && tick % 30 == 0 {
                let video_crc = machine
                    .red_label_visible_video_crc32()
                    .expect("video CRC remains available");
                if tick == 900 {
                    title_video_crc = Some(video_crc);
                }
                if let Some(title_video_crc) = title_video_crc {
                    saw_post_title_video |= tick > 900 && video_crc != title_video_crc;
                }
            }
            saw_instruction_scene_process |= machine
                .memory
                .active_process_has_routine(&instruction_scene_routines)
                .expect("query instruction scene processes");
            if saw_post_title_video && saw_instruction_scene_process {
                break;
            }
        }

        assert!(
            saw_post_title_video,
            "live attract did not visibly leave the title page"
        );
        assert!(
            saw_instruction_scene_process,
            "live attract did not schedule the instruction scene"
        );
        assert_eq!(
            machine.red_label_ram_range(RED_LABEL_THSTAB_START..todays_end),
            Some(todays_before.as_slice())
        );
    }

