    #[test]
    fn player_motion_respects_status_and_vertical_limits() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        machine.memory.write_byte(0xA0BA, 0x40).expect("set STATUS");
        machine.memory.write_byte(0xA07B, 0x82).expect("set PIA21");
        assert_eq!(
            machine
                .red_label_update_player_motion_from_pia()
                .expect("blocked PLAYER motion"),
            RedLabelPlayerMotion::StatusBlocked { status: 0x40 }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0C7..0xA0CC),
            Some(&[0, 0, 0, 0, 0][..])
        );

        machine.memory.write_byte(0xA0BA, 0).expect("clear STATUS");
        machine
            .memory
            .write_word(0xA0C5, 0xEE00)
            .expect("set PLAY16");
        machine.memory.write_byte(0xA07B, 0x80).expect("hold down");
        assert_eq!(
            machine
                .red_label_update_player_motion_from_pia()
                .expect("limit PLAYER motion"),
            RedLabelPlayerMotion::VerticalLimitBlocked {
                status: 0,
                pia21: 0x80,
                pia31: 0,
                player_velocity: [0, 0, 0],
                player_calculated_x: 0x2000,
                player_x16: 0x2000,
                background_delta: 0,
                background_left: 0,
                absolute_x: 0x0800,
                player_y_velocity: 0,
                player_y16: 0xEE00,
                next_player_x: 0x20,
            }
        );
    }

    #[test]
    fn player_display_draws_on86_picture_and_erases_old_footprint() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        seed_thrust_table(&mut machine);
        let old_picture = red_label_object_picture_address("PLAPIC").expect("PLAPIC address");
        write_object_footprint(&mut machine, 0x2080, old_picture, 0xCC);
        write_forward_thrust_footprint(&mut machine, 0x2080, 0xCC);
        machine
            .memory
            .write_byte(0xA07B, 0x02)
            .expect("hold thrust");
        machine
            .memory
            .write_word(0xA0BB, 0xFD00)
            .expect("set NPLAD left");
        machine
            .memory
            .write_word(0xA0C1, 0x3070)
            .expect("set NPLAXC");
        machine
            .memory
            .write_word(0xA0C3, 0x2080)
            .expect("set PLAX16 alternate flavor");

        let display = machine
            .red_label_display_player_picture_in_band(0x90, 0x70)
            .expect("PRDISP player picture");

        assert_eq!(
            display,
            RedLabelPlayerDisplay::Updated {
                status: 0,
                upper_bound: 0x90,
                lower_bound: 0x70,
                old_screen_address: 0x2080,
                old_direction: 0x0300,
                erased_old_picture: true,
                new_direction: 0xFD00,
                new_screen_address: 0x3070,
                picture_address: 0xF9CB,
                alternate_flavor: true,
            }
        );
        assert_object_footprint_cleared(&machine, 0x2080, old_picture);
        assert_eq!(
            machine.red_label_ram_range(0x3070..0x3076),
            Some(&[0x00, 0x00, 0x00, 0x00, 0x03, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3170..0x3176),
            Some(&[0x00, 0x00, 0x00, 0x00, 0x96, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x1F81..0x1F86),
            Some(&[0; 5][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3871..0x3876),
            Some(&[0x10, 0x11, 0x12, 0x13, 0x14][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3972..0x3975),
            Some(&[0x15, 0x16, 0x17][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3A72..0x3A75),
            Some(&[0x1A, 0x1B, 0x18][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3B73..0x3B74),
            Some(&[0x19][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA077..0xA078),
            Some(&[0x90][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BB..0xA0C5),
            Some(&[0xFD, 0x00, 0xFD, 0x00, 0x30, 0x70, 0x30, 0x70, 0x20, 0x80][..])
        );
    }

