    #[test]
    fn scinit_prepares_attract_scene_world_and_video_state() {
        let mut machine = ArcadeMachine::new();
        let allocated_object = machine
            .memory
            .get_object_cell()
            .expect("allocate dirty object");
        machine
            .memory
            .activate_object_cell(allocated_object)
            .expect("dirty active object list");
        machine
            .memory
            .write_byte(0x4000, 0xEE)
            .expect("dirty video byte");
        machine
            .memory
            .write_byte(0x97FF, 0xEE)
            .expect("dirty final video byte");
        machine
            .memory
            .write_word(0xA020, 0x2220)
            .expect("dirty BGL");
        machine
            .memory
            .write_word(0xA022, 0x3330)
            .expect("dirty BGLX");
        machine
            .memory
            .write_word(0xA00B, 0x2F20)
            .expect("dirty RTPTR");
        machine
            .memory
            .write_byte(0xA026, 0xEE)
            .expect("dirty PCRAM");
        machine
            .memory
            .write_byte(0xA036, 0x02)
            .expect("dirty MAPCR");
        machine
            .memory
            .write_byte(0xA0BA, 0x12)
            .expect("dirty STATUS");
        machine
            .memory
            .write_word(0xA0BF, 0xFFFF)
            .expect("dirty PLAXC");
        machine
            .memory
            .write_word(0x9C00, 0xAF00)
            .expect("dirty appearance size");
        machine
            .memory
            .write_word(0x9FFC, 0x7788)
            .expect("dirty final appearance slot bytes");

        let init = machine
            .red_label_initialize_attract_scene_from_scinit()
            .expect("SCINIT attract setup");

        assert_eq!(
            init,
            RedLabelAttractSceneInit {
                initial_status: 0xFF,
                screen_clear: screen_clear(),
                altitude_table: expected_alinit(),
                background: RedLabelBackgroundInit {
                    bgi_address: red_label_routine_address("BGI").expect("BGI address"),
                    selected_map: 7,
                    terrain_tables: expected_bginit(),
                },
                color_ram: RedLabelColorRamInit {
                    source_label: String::from("CRTAB"),
                    source_address: 0xF8BE,
                    target_start: 0xA026,
                    target_end: 0xA036,
                    bytes: CRTAB_BYTES.to_vec(),
                },
                final_status: 0xDB,
                player_scanner_center: 0x1030,
            }
        );
        assert_eq!(machine.memory.ram_range(0x4000..0x4001), Some(&[0][..]));
        assert_eq!(machine.memory.ram_range(0x97FF..0x9800), Some(&[0][..]));
        assert_eq!(
            machine.memory.ram_range(0xA020..0xA024),
            Some(&[0, 0, 0, 0][..])
        );
        assert_eq!(
            machine.memory.ram_range(0xA026..0xA036),
            Some(&CRTAB_BYTES[..])
        );
        assert_eq!(machine.memory.ram_range(0xA036..0xA037), Some(&[7][..]));
        assert_eq!(
            machine.memory.ram_range(0xA065..0xA069),
            Some(&[0, 0, 0xA2, 0x3C][..])
        );
        assert_eq!(machine.memory.ram_range(0xA0BA..0xA0BB), Some(&[0xDB][..]));
        assert_eq!(
            machine.memory.ram_range(0xA0BF..0xA0C1),
            Some(&[0x10, 0x30][..])
        );
        assert_eq!(
            machine.memory.ram_range(0x9C00..0xA000),
            Some(&[0; 0x0400][..])
        );
        assert_eq!(
            machine.memory.ram_range(0xA23C..0xA23E),
            Some(&[0xA2, 0x53][..])
        );
    }

    #[test]
    fn bgout_draws_selected_terrain_flavor_and_updates_stbl() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        memory
            .initialize_altitude_table_from_tdata()
            .expect("ALINIT altitude table");
        memory
            .initialize_terrain_tables_from_bgl()
            .expect("BGINIT terrain tables");
        for (entry, old_screen_address) in [0x4000, 0x4002, 0x4010].into_iter().enumerate() {
            let table_entry = 0xBE20 + if entry == 2 { 0x10 } else { entry as u16 * 2 };
            memory
                .write_word(table_entry, old_screen_address)
                .expect("seed old terrain screen address");
            memory
                .write_word(old_screen_address, 0x2222)
                .expect("seed old terrain word");
        }

        let output = memory
            .output_terrain_from_bgl(0x1234)
            .expect("BGOUT terrain output");

        assert_eq!(output, expected_bgout_default(0x1234));
        assert_eq!(
            memory.ram_range(0xA013..0xA017),
            Some(&[0x12, 0x34, 0x00, 0x00][..])
        );
        assert_eq!(
            memory.ram_range(0xBE20..0xBE30),
            Some(
                &[
                    0x98, 0xDE, 0x97, 0xDE, 0x96, 0xDE, 0x95, 0xDC, 0x94, 0xDA, 0x93, 0xD8, 0x92,
                    0xD7, 0x91, 0xD9,
                ][..]
            )
        );
        assert_eq!(memory.ram_range(0x98DE..0x98E0), Some(&[0x70, 0x07][..]));
        assert_eq!(memory.ram_range(0x97DE..0x97E0), Some(&[0x70, 0x07][..]));
        assert_eq!(memory.ram_range(0x92D7..0x92D9), Some(&[0x07, 0x70][..]));
        assert_eq!(memory.ram_range(0x4000..0x4002), Some(&[0, 0][..]));
        assert_eq!(memory.ram_range(0x4002..0x4004), Some(&[0, 0][..]));
        assert_eq!(memory.ram_range(0x4010..0x4012), Some(&[0, 0][..]));
    }

    #[test]
    fn bgeras_clears_screen_words_from_stbl_without_mutating_table() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        for (slot, screen_address) in [0x4000, 0x4100, 0x4200].into_iter().enumerate() {
            memory
                .write_word(0xBE20 + (slot as u16 * 2), screen_address)
                .expect("seed STBL entry");
            memory
                .write_word(screen_address, 0x7777)
                .expect("dirty terrain screen word");
        }
        memory.write_word(0x0000, 0x5555).expect("dirty zero entry");

        let erase = memory
            .erase_terrain_from_screen_table()
            .expect("BGERAS terrain erase");

        assert_eq!(
            erase,
            RedLabelTerrainErase {
                table_start: 0xBE20,
                table_end: 0xBF50,
                entries: 0x98,
            }
        );
        assert_eq!(memory.ram_range(0x0000..0x0002), Some(&[0, 0][..]));
        assert_eq!(memory.ram_range(0x4000..0x4002), Some(&[0, 0][..]));
        assert_eq!(memory.ram_range(0x4100..0x4102), Some(&[0, 0][..]));
        assert_eq!(memory.ram_range(0x4200..0x4202), Some(&[0, 0][..]));
        assert_eq!(
            memory.ram_range(0xBE20..0xBE26),
            Some(&[0x40, 0x00, 0x41, 0x00, 0x42, 0x00][..])
        );
    }

    #[test]
    fn world_terrain_fixture_covers_bgout_scanner_terblo_and_restore_wave() {
        let mut terrain = ArcadeMachine::new();
        terrain
            .red_label_initialize_altitude_table()
            .expect("DC-10.2 ALINIT");
        terrain
            .red_label_initialize_terrain_tables()
            .expect("DC-10.2 BGINIT");
        let stbl_head = red_label_ram_snapshot(&terrain, "DC-10.2 STBL head", 0xBE20..0xBE30);
        let terrain_output = terrain
            .red_label_output_terrain(red_label_irq_bgout_stack_pointer())
            .expect("DC-10.2 BGOUT");

        assert_eq!(
            terrain_output,
            expected_bgout_default(red_label_irq_bgout_stack_pointer())
        );
        stbl_head.assert_current_changed_to(
            &terrain,
            &[
                0x98, 0xDE, 0x97, 0xDE, 0x96, 0xDE, 0x95, 0xDC, 0x94, 0xDA, 0x93, 0xD8, 0x92, 0xD7,
                0x91, 0xD9,
            ],
        );
        assert_eq!(
            terrain.red_label_ram_range(0xA013..0xA015),
            Some(&red_label_irq_bgout_stack_pointer().to_be_bytes()[..])
        );

        let mut scanner = ArcadeMachine::new();
        let raster = scanner
            .red_label_draw_scanner_raster()
            .expect("DC-10.2 scanner raster");
        let terrain_blips = raster.terrain_blips.expect("DC-10.2 terrain blips");
        assert_eq!(terrain_blips.len(), 64);
        assert_eq!(terrain_blips[0].erase_table_address, 0xB125);
        assert_eq!(terrain_blips[0].screen_address >> 8, 0x30);
        assert_eq!(
            scanner.red_label_ram_range(
                terrain_blips[0].screen_address..terrain_blips[0].screen_address + 2
            ),
            Some(&terrain_blips[0].word.to_be_bytes()[..])
        );

        let mut destroyed = ArcadeMachine::new();
        let process = destroyed
            .red_label_make_process(
                red_label_routine_address("TERBLO").expect("TERBLO address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make DC-10.2 TERBLO process")
            .process_address;
        destroyed
            .step_red_label_process_scheduler()
            .expect("schedule DC-10.2 TERBLO");
        let status = red_label_ram_snapshot(&destroyed, "DC-10.2 terrain status", 0xA0BA..0xA0BB);
        let step = destroyed
            .red_label_start_terrain_blow_current_process()
            .expect("DC-10.2 TERBLO start");
        let RedLabelTerrainBlowProcessStep::StartedSleeping {
            process_address,
            status: terrain_status,
            terrain_erase,
            scanner_terrain_erase,
            pass,
        } = step
        else {
            panic!("expected DC-10.2 TERBLO start");
        };
        assert_eq!(process_address, process);
        assert_eq!(terrain_status & 0x02, 0x02);
        assert_eq!(terrain_erase.entries, 0x98);
        assert_eq!(scanner_terrain_erase.entries, 64);
        assert_eq!(pass.explosions.len(), 2);
        assert_eq!(
            pass.wakeup_address,
            red_label_routine_address("TBL3").expect("TBL3 address")
        );
        status.assert_current_changed_to(&destroyed, &[0x02]);

        let mut restore = ArcadeMachine::new();
        restore.memory.write_byte(0xA1CA, 4).expect("set PWAV");
        restore.memory.write_byte(0xA1CC, 0).expect("clear PTARG");
        let wave = restore
            .red_label_get_new_wave_parameters_for_player_address(0xA1C2)
            .expect("DC-10.2 GETWV restore");
        assert_eq!(wave.previous_wave, 4);
        assert_eq!(wave.wave, 5);
        assert!(wave.restored_humans);
        assert_eq!(restore.red_label_ram_range(0xA1CC..0xA1CD), Some(&[10][..]));
    }

    #[test]
    fn machine_boot_initializes_source_init20_tables_from_rand() {
        let machine = ArcadeMachine::new();
        let mut rng = RandState::default();
        let mut expected_fizzle = [0; 0x20];
        for byte in &mut expected_fizzle {
            rng.advance();
            *byte = laser_fizzle_byte(rng.seed);
        }

        let (stars, star_rand_values_consumed) =
            star_table_from_rand_values(std::iter::from_fn(|| {
                rng.advance();
                Some(rng.seed)
            }))
            .expect("STINIT values");
        let mut expected_stars = [0; 0x40];
        for (index, star) in stars.iter().copied().enumerate() {
            let offset = index * 4;
            expected_stars[offset] = star.x;
            expected_stars[offset + 1] = star.y;
            expected_stars[offset + 2] = star.color;
        }

        let mut expected_fireballs = [0; 0x20];
        for byte in &mut expected_fireballs {
            rng.advance();
            *byte = fireball_table_byte(rng.seed);
        }

        let mut thrust_rand = [0; 33];
        for byte in &mut thrust_rand {
            rng.advance();
            *byte = rng.seed;
        }
        let mut expected_thrust = [0; 0x40];
        for (offset, value) in thrust_rand.iter().copied().enumerate() {
            if 32 + offset < expected_thrust.len() {
                expected_thrust[32 + offset] = value;
            }
            if offset < expected_thrust.len() {
                expected_thrust[offset] = value;
            }
        }
        expected_fireballs[0] = thrust_rand[32];

        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA036),
            Some(&CRTAB_BYTES[..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0A4..0xA0A6),
            Some(&[0xA1, 0x42][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA142..0xA162),
            Some(&expected_fizzle[..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0AE..0xA0AF),
            Some(&[0x10][..])
        );
        assert_eq!(star_rand_values_consumed, 56);
        assert_eq!(
            machine.red_label_ram_range(0xAF9D..0xAFDD),
            Some(&expected_stars[..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0A8..0xA0AA),
            Some(&[0xA1, 0xA2][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA1A2..0xA1C2),
            Some(&expected_fireballs[..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09F..0xA0A1),
            Some(&[0xA1, 0x62][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA162..0xA1A2),
            Some(&expected_thrust[..])
        );
        assert_eq!(machine.snapshot().rng, rng);
    }

    #[test]
    fn fiss_maps_rand_bits_into_fizzle_table_and_sets_fisx() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        let mut rand_values = [0; 0x20];
        for (index, value) in rand_values.iter_mut().enumerate() {
            *value = (index % 4) as u8;
        }

        let init = memory
            .initialize_laser_fizzle_table_from_rand_values(&rand_values)
            .expect("FISS");

        assert_eq!(
            init,
            RedLabelLaserFizzleInit {
                table_start: 0xA142,
                table_end: 0xA162,
                fizzle_index: 0xA142,
            }
        );
        assert_eq!(memory.ram_range(0xA0A4..0xA0A6), Some(&[0xA1, 0x42][..]));
        assert_eq!(
            memory.ram_range(0xA142..0xA14A),
            Some(&[0x00, 0x01, 0x10, 0x11, 0x00, 0x01, 0x10, 0x11][..])
        );
    }

