    #[test]
    fn stinit_rejects_invalid_rand_coordinates_and_cycles_colors() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        let mut rand_values = vec![0x9C, 0x20, 0xA9, RED_LABEL_Y_MIN, RED_LABEL_Y_MIN + 1];
        for index in 1..16 {
            rand_values.push(0x30 + index as u8);
            rand_values.push(0x40 + index as u8);
        }

        let init = memory
            .initialize_star_table_from_rand_values(&rand_values)
            .expect("STINIT");

        assert_eq!(
            init,
            RedLabelStarTableInit {
                table_start: 0xAF9D,
                table_end: 0xAFDD,
                star_count: 16,
                rand_values_consumed: 35,
            }
        );
        assert_eq!(memory.ram_range(0xA0AE..0xA0AF), Some(&[0x10][..]));
        assert_eq!(
            memory.ram_range(0xAF9D..0xAFA2),
            Some(&[0x20, 0x2B, 0x00, 0x00, 0x31][..])
        );
        assert_eq!(memory.ram_range(0xAF9F..0xAFA0), Some(&[0x00][..]));
        assert_eq!(memory.ram_range(0xAFBB..0xAFBC), Some(&[0x77][..]));
        assert_eq!(memory.ram_range(0xAFBF..0xAFC0), Some(&[0x00][..]));
        assert_eq!(memory.ram_range(0xAFDB..0xAFDC), Some(&[0x77][..]));
    }

