    #[test]
    fn descriptor_erase_clears_columnar_eight_row_trailing_byte() {
        let mut machine = ArcadeMachine::new();
        let screen_address = 0x785F;
        let picture_address = red_label_object_picture_address("ASTP1").expect("ASTP1 address");
        let picture = red_label_object_picture(picture_address).expect("ASTP1 picture");
        write_object_footprint(&mut machine, screen_address, picture_address, 0x07);
        for column in 0..picture.width {
            let trailing_address =
                screen_address + (u16::from(column) << 8) + u16::from(picture.height);
            machine
                .memory
                .write_byte(trailing_address, 0x07)
                .expect("seed trailing byte");
        }

        let clear = machine
            .red_label_erase_object_picture_by_descriptor(screen_address, picture_address)
            .expect("OFF28 descriptor erase")
            .expect("ASTP1 erases");

        assert_eq!(
            clear,
            RedLabelBlockClear {
                screen_address,
                width: 2,
                height: 9,
            }
        );
        assert_object_footprint_cleared(&machine, screen_address, picture_address);
        for column in 0..picture.width {
            let trailing_address =
                screen_address + (u16::from(column) << 8) + u16::from(picture.height);
            assert_eq!(
                machine.red_label_ram_range(trailing_address..trailing_address + 1),
                Some(&[0][..]),
                "columnar object trailing byte 0x{trailing_address:04X} was not cleared"
            );
        }
    }

    #[test]
    fn object_display_band_erases_old_and_writes_new_descriptor_picture() {
        let mut machine = ArcadeMachine::new();
        let picture_address = red_label_object_picture_address("BMBP1").expect("BMBP1 address");
        let object = setup_active_display_object(&mut machine, "BMBP1");
        machine.memory.write_word(0xA020, 0x1000).expect("set BGL");
        machine
            .memory
            .write_word(object + 0x04, 0x304C)
            .expect("set old object screen address");
        machine
            .memory
            .write_word(object + 0x0A, 0x1420)
            .expect("set object OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x5055)
            .expect("set object OY16");
        write_object_footprint(&mut machine, 0x304C, picture_address, 0xCC);

        let display = machine
            .red_label_process_active_objects_in_band(0x60, 0x40)
            .expect("OPROC active-object display");

        assert_eq!(
            display,
            RedLabelObjectDisplayBand::Updated {
                status: 0,
                upper_bound: 0x60,
                lower_bound: 0x40,
                objects: vec![RedLabelObjectDisplay {
                    object_address: object,
                    picture_address,
                    old_screen_address: Some(0x304C),
                    erased_old_picture: Some(RedLabelBlockClear {
                        screen_address: 0x304C,
                        width: 2,
                        height: 3,
                    }),
                    relative_x: Some(0x0420),
                    new_screen_address: Some(0x1050),
                    alternate_flavor: Some(true),
                    written_picture: Some(RedLabelPictureWrite {
                        screen_address: 0x1050,
                        picture_address,
                        width: 2,
                        height: 3,
                    }),
                }],
            }
        );
        assert_object_footprint_cleared(&machine, 0x304C, picture_address);
        assert_object_image_written(&machine, 0x1050, picture_address, 0xCCB6);
        assert_eq!(
            machine.red_label_ram_range(object + 0x04..object + 0x06),
            Some(&[0x10, 0x50][..])
        );
    }

