    #[test]
    fn active_object_velocity_advances_active_list_and_wraps_y_bounds() {
        let mut machine = ArcadeMachine::new();
        let first = setup_active_display_object(&mut machine, "BMBP1");
        let second = setup_active_display_object(&mut machine, "BMBP1");
        machine
            .memory
            .write_word(first + 0x0A, 0x1000)
            .expect("set first OX16");
        machine
            .memory
            .write_word(first + 0x0C, 0x2A00)
            .expect("set first OY16");
        machine
            .memory
            .write_word(first + 0x0E, 0xFFFE)
            .expect("set first OXV");
        machine
            .memory
            .write_word(first + 0x10, 0xFF00)
            .expect("set first OYV");
        machine
            .memory
            .write_word(second + 0x0A, 0xFFF0)
            .expect("set second OX16");
        machine
            .memory
            .write_word(second + 0x0C, 0xF000)
            .expect("set second OY16");
        machine
            .memory
            .write_word(second + 0x0E, 0x0020)
            .expect("set second OXV");
        machine
            .memory
            .write_word(second + 0x10, 0x0100)
            .expect("set second OYV");

        let velocity = machine
            .red_label_advance_active_object_velocities()
            .expect("VELO active objects");

        assert_eq!(
            velocity,
            RedLabelObjectVelocityUpdate::Updated {
                status: 0,
                objects: vec![
                    RedLabelObjectVelocityStep {
                        object_address: second,
                        previous_x16: 0xFFF0,
                        x_velocity: 0x0020,
                        x16: 0x0010,
                        previous_y16: 0xF000,
                        y_velocity: 0x0100,
                        y16: 0x2A00,
                    },
                    RedLabelObjectVelocityStep {
                        object_address: first,
                        previous_x16: 0x1000,
                        x_velocity: 0xFFFE,
                        x16: 0x0FFE,
                        previous_y16: 0x2A00,
                        y_velocity: 0xFF00,
                        y16: 0xF000,
                    },
                ],
            }
        );
        assert_eq!(
            machine.red_label_ram_range(second + 0x0A..second + 0x0E),
            Some(&[0x00, 0x10, 0x2A, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(first + 0x0A..first + 0x0E),
            Some(&[0x0F, 0xFE, 0xF0, 0x00][..])
        );
    }

