    #[test]
    fn runtime_step_translated_process_dispatches_with_source_disp_context() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SUCIDE").expect("SUCIDE address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make translated process")
            .process_address;

        let dispatch = machine
            .memory
            .step_translated_process()
            .expect("translated process step")
            .expect("scheduled process");

        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::Suicide(RedLabelKilledProcess {
                killed_process_address: process,
                previous_link_address: 0xA05F,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&process.to_be_bytes()[..])
        );
    }

    #[test]
    fn player_restore_rejects_mismatched_pls1_entry_u_without_mutation() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PLS1").expect("PLS1 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLS1 process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule PLS1");
        let active_before = machine
            .red_label_ram_range(0xA05F..0xA061)
            .expect("active head")
            .to_vec();
        let free_before = machine
            .red_label_ram_range(0xA061..0xA063)
            .expect("free head")
            .to_vec();
        let mut registers = RedLabelCpuRegisters::from_source_disp(process.wrapping_add(2));
        registers.b = Some(RED_LABEL_PLS1_ENTRY_B_REGISTER);

        let error = machine
            .memory
            .finish_player_start_current_process_with_entry_registers(registers)
            .expect_err("mismatched PLS1 entry U should fail before PLRES mutation");

        assert!(error.contains("entry U"));
        assert!(error.contains(&format!("0x{process:04X}")));
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&active_before[..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&free_before[..])
        );
    }

    #[test]
    fn player_restore_requires_pls1_entry_b_for_targetless_swarmer_restore() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PLS1").expect("PLS1 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLS1 process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule PLS1");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        machine.memory.write_byte(0xA1CC, 0).expect("clear PTARG");
        let active_before = machine
            .red_label_ram_range(0xA05F..0xA061)
            .expect("active head")
            .to_vec();
        let free_before = machine
            .red_label_ram_range(0xA061..0xA063)
            .expect("free head")
            .to_vec();

        let error = machine
            .memory
            .finish_player_start_current_process_with_entry_registers(
                RedLabelCpuRegisters::from_source_disp(process),
            )
            .expect_err("missing PLS1 entry B should fail before PLRES mutation");

        assert!(error.contains("PLRES"));
        assert!(error.contains("entry B"));
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&active_before[..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&free_before[..])
        );
    }

    #[test]
    fn process_scheduler_waits_when_ptime_remains_nonzero() {
        let mut machine = ArcadeMachine::new();
        machine
            .memory
            .write_word(0xA05F, 0xAAC5)
            .expect("active head");
        machine
            .memory
            .write_word(0xAAC5, 0)
            .expect("single active process");
        machine
            .memory
            .write_word(0xAAC7, 0x1234)
            .expect("process address");
        machine.memory.write_byte(0xAAC9, 2).expect("process time");

        let scheduled = machine
            .step_red_label_process_scheduler()
            .expect("scheduler step");

        assert_eq!(scheduled, None);
        assert_eq!(machine.red_label_ram_range(0xAAC9..0xAACA), Some(&[1][..]));
    }

    #[test]
    fn make_process_matches_newp_macro_and_inserts_at_crproc_link() {
        let mut machine = ArcadeMachine::new();

        let created = machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make process");

        assert_eq!(
            created,
            RedLabelCreatedProcess {
                process_address: 0xAAC5,
                routine_address: 0x1234,
                process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                class: RedLabelProcessClass::Regular,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0xAA, 0xC5][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&[0xAA, 0xD4][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAC5..0xAACA),
            Some(&[0x00, 0x00, 0x12, 0x34, 0x01][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAACA..0xAACC),
            Some(&[RED_LABEL_SYSTEM_PROCESS_TYPE, 0x00][..])
        );

        let scheduled = machine
            .step_red_label_process_scheduler()
            .expect("scheduler step");
        assert_eq!(
            scheduled,
            Some(RedLabelScheduledProcess::from_source_disp(0xAAC5, 0x1234))
        );

        let second = machine
            .red_label_make_process(0x5678, RED_LABEL_ATTRACT_PROCESS_TYPE)
            .expect("make process after CRPROC");

        assert_eq!(second.process_address, 0xAAD4);
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0xAA, 0xC5][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAC5..0xAAC7),
            Some(&[0xAA, 0xD4][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAD4..0xAAD9),
            Some(&[0x00, 0x00, 0x56, 0x78, 0x01][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAD9..0xAADB),
            Some(&[RED_LABEL_ATTRACT_PROCESS_TYPE, 0x00][..])
        );
    }

    #[test]
    fn switch_table_asset_captures_all_swtab_entries() {
        let entries = red_label_switch_table().expect("switch table");
        let entry = |switch_bit| {
            entries
                .iter()
                .find(|entry| entry.switch_bit == switch_bit)
                .unwrap_or_else(|| panic!("missing switch bit 0x{switch_bit:02X}"))
        };

        assert_eq!(entries.len(), 8);
        assert_eq!(entry(0x01).name, "fire");
        assert_eq!(entry(0x01).routine_label.as_deref(), Some("LFIRE"));
        assert_eq!(
            entry(0x01).process_type,
            Some(RED_LABEL_SYSTEM_PROCESS_TYPE)
        );
        assert_eq!(entry(0x01).status_mask, Some(0xE8));
        assert_eq!(entry(0x02).name, "thrust");
        assert_eq!(entry(0x02).routine_label, None);
        assert_eq!(entry(0x04).routine_label.as_deref(), Some("SBOMB"));
        assert_eq!(entry(0x04).status_mask, Some(0xF8));
        assert_eq!(entry(0x08).routine_label.as_deref(), Some("HYPER"));
        assert_eq!(entry(0x08).status_mask, Some(0xF8));
        assert_eq!(entry(0x10).routine_label.as_deref(), Some("ST2"));
        assert_eq!(entry(0x20).routine_label.as_deref(), Some("ST1"));
        assert_eq!(entry(0x40).routine_label.as_deref(), Some("REV"));
        assert_eq!(entry(0x40).status_mask, Some(0xE8));
        assert_eq!(entry(0x80).name, "altitude_down");
        assert_eq!(entry(0x80).routine_label, None);
    }

