    #[test]
    fn switch_process_dispatch_honors_status_mask_and_creates_lfire_process() {
        let mut machine = ArcadeMachine::new();
        machine
            .red_label_scan_translated_player_switches(DefenderInputPorts {
                in0: 0x01,
                in1: 0,
                in2: 0,
            })
            .expect("queue fire");
        machine
            .memory
            .write_byte(0xA0BA, 0x40)
            .expect("set controls-inactive status");

        assert_eq!(
            machine
                .red_label_dispatch_switch_processes()
                .expect("blocked dispatch"),
            Vec::new()
        );
        assert_eq!(
            machine.red_label_ram_range(0xA082..0xA086),
            Some(&[0x00, 0x00, RED_LABEL_SYSTEM_PROCESS_TYPE, 0xE8][..])
        );

        machine
            .memory
            .write_byte(0xA0BA, 0x00)
            .expect("clear status");
        machine
            .red_label_scan_translated_player_switches(DefenderInputPorts::EMPTY)
            .expect("release fire");
        machine
            .red_label_scan_translated_player_switches(DefenderInputPorts::EMPTY)
            .expect("second clear sample");
        machine
            .red_label_scan_translated_player_switches(DefenderInputPorts {
                in0: 0x01,
                in1: 0,
                in2: 0,
            })
            .expect("queue fire again");

        let created = machine
            .red_label_dispatch_switch_processes()
            .expect("dispatch fire switch");
        assert_eq!(
            created,
            vec![RedLabelCreatedProcess {
                process_address: 0xAAC5,
                routine_address: red_label_routine_address("LFIRE").expect("LFIRE address"),
                process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                class: RedLabelProcessClass::Regular,
            }]
        );
    }

