    #[test]
    fn kill_object_cell_searches_active_list_then_returns_cell_to_ofree() {
        let mut machine = ArcadeMachine::new();
        let first = machine
            .red_label_get_object_cell()
            .expect("first object cell");
        machine
            .red_label_activate_object_cell(first)
            .expect("activate first");
        let second = machine
            .red_label_get_object_cell()
            .expect("second object cell");
        machine
            .red_label_activate_object_cell(second)
            .expect("activate second");

        let previous_link = machine
            .red_label_kill_object_cell(first)
            .expect("kill first object");

        assert_eq!(previous_link, second);
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&[0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(second..second + 2),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x3C][..])
        );
        assert_eq!(
            machine.red_label_ram_range(first..first + 2),
            Some(&[0xA2, 0x6A][..])
        );
    }

