    #[test]
    fn scanner_process_runs_source_scan_stages_and_sleep_cadence() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SCPROC").expect("SCPROC address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make SCPROC process")
            .process_address;

        let inactive_stage = machine
            .step_red_label_translated_process()
            .expect("dispatch SCPROC")
            .expect("scheduled SCPROC");
        assert_eq!(
            inactive_stage,
            RedLabelProcessDispatch::ScannerProcess(
                RedLabelScannerProcessStep::InactiveScannedSleeping {
                    process_address: process,
                    activated_objects: Vec::new(),
                    wakeup_address: red_label_routine_address("SCP1").expect("SCP1 address"),
                }
            )
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE9, 0xEE, 0x02][..])
        );
        assert_eq!(
            machine
                .step_red_label_translated_process()
                .expect("SCP1 sleep tick"),
            None
        );

        let active_stage = machine
            .step_red_label_translated_process()
            .expect("dispatch SCP1")
            .expect("scheduled SCP1");
        assert_eq!(
            active_stage,
            RedLabelProcessDispatch::ScannerProcess(
                RedLabelScannerProcessStep::ActiveAndShellScannedSleeping {
                    process_address: process,
                    deactivated_objects: Vec::new(),
                    reclaimed_shells: Vec::new(),
                    wakeup_address: red_label_routine_address("SCP2").expect("SCP2 address"),
                }
            )
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE9, 0xFC, 0x02][..])
        );
        assert_eq!(
            machine
                .step_red_label_translated_process()
                .expect("SCP2 sleep tick"),
            None
        );

        let display_stage = machine
            .step_red_label_translated_process()
            .expect("dispatch SCP2")
            .expect("scheduled SCP2");
        let RedLabelProcessDispatch::ScannerProcess(
            RedLabelScannerProcessStep::ScannerDisplaySleeping {
                process_address,
                scanner_vector_address,
                raster,
                wakeup_address,
            },
        ) = display_stage
        else {
            panic!("expected SCP2 display dispatch");
        };
        assert_eq!(process_address, process);
        assert_eq!(
            scanner_vector_address,
            red_label_routine_address("SCNRV").expect("SCNRV address")
        );
        assert_eq!(
            wakeup_address,
            red_label_routine_address("SCPROC").expect("SCPROC address")
        );
        assert_eq!(raster.scanner_vector_address, scanner_vector_address);
        assert_eq!(raster.selected_map, 1);
        assert_eq!(raster.old_object_blip_words_cleared, 0);
        assert_eq!(raster.active_object_blips, Vec::new());
        assert_eq!(raster.inactive_object_blips, Vec::new());
        assert_eq!(raster.setend, 0xB05D);
        assert_eq!(
            raster.player_blip,
            RedLabelScannerPlayerBlip {
                erase_table_address: 0xB05D,
                previous_screen_address: None,
                screen_address: 0x4B07,
            }
        );
        let terrain_blips = raster.terrain_blips.expect("terrain drawn");
        assert_eq!(terrain_blips.len(), 64);
        assert_eq!(terrain_blips[0].erase_table_address, 0xB125);
        assert_eq!(terrain_blips[0].screen_address >> 8, 0x30);
        assert_eq!(
            machine.red_label_ram_range(
                terrain_blips[0].screen_address..terrain_blips[0].screen_address + 2
            ),
            Some(&terrain_blips[0].word.to_be_bytes()[..])
        );
        assert_eq!(machine.red_label_ram_range(0xA036..0xA037), Some(&[1][..]));
        assert_eq!(
            machine.red_label_ram_range(0x4B07..0x4B0A),
            Some(&[0x90, 0x99, 0x90][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE9, 0xE3, 0x04][..])
        );
    }

    #[test]
    fn scanner_raster_clears_old_blips_and_draws_objects_and_player() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make process")
            .process_address;
        let active = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("PLAPIC")
                        .expect("PLAPIC address"),
                    collision_vector_address: red_label_routine_address("NOKILL")
                        .expect("NOKILL address"),
                    scanner_color: 0x1234,
                },
            )
            .expect("init active object")
            .object_address;
        machine
            .red_label_activate_object_cell(active)
            .expect("activate object");
        let inactive = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("PLAPIC")
                        .expect("PLAPIC address"),
                    collision_vector_address: red_label_routine_address("NOKILL")
                        .expect("NOKILL address"),
                    scanner_color: 0xABCD,
                },
            )
            .expect("init inactive object")
            .object_address;
        machine
            .memory
            .write_word(inactive, 0)
            .expect("terminate inactive object");
        machine
            .memory
            .write_word(0xA06B, inactive)
            .expect("set IPTR");

        machine
            .memory
            .write_byte(0xA0BA, 0x02)
            .expect("disable terrain");
        machine.memory.write_word(0xA020, 0x2000).expect("set BGL");
        machine
            .memory
            .write_word(active + 0x0A, 0x2100)
            .expect("active OX16");
        machine
            .memory
            .write_word(active + 0x0C, 0x5000)
            .expect("active OY16");
        machine
            .memory
            .write_word(inactive + 0x0A, 0x2300)
            .expect("inactive OX16");
        machine
            .memory
            .write_word(inactive + 0x0C, 0x6800)
            .expect("inactive OY16");
        machine
            .memory
            .write_word(0xA0BF, 0x8040)
            .expect("set PLAXC");

        for (entry, screen) in [
            (0xB05D, 0x3010),
            (0xB05F, 0x3012),
            (0xB061, 0x3014),
            (0xB063, 0x3016),
        ] {
            machine
                .memory
                .write_word(entry, screen)
                .expect("seed SETAB");
            machine
                .memory
                .write_word(screen, 0xFFFF)
                .expect("seed old scanner object");
        }
        machine
            .memory
            .write_word(0xA097, 0xB065)
            .expect("set SETEND");
        machine
            .memory
            .write_word(0xB065, 0x4B20)
            .expect("seed old player pointer");
        machine
            .memory
            .write_word(0x4B20, 0xFFFF)
            .expect("seed old player body");
        machine
            .memory
            .write_byte(0x4B22, 0xFF)
            .expect("seed old player tail");
        machine
            .memory
            .write_word(0x4A20, 0xFFFF)
            .expect("seed old player upper word");

        let raster = machine
            .red_label_draw_scanner_raster()
            .expect("draw scanner raster");

        let scan_left = 0x2000u16.wrapping_sub(0x8000u16.wrapping_sub(150 * 32));
        let active_screen = scanner_object_screen_address_for_test(0x2100, 0x5000, scan_left);
        let inactive_screen = scanner_object_screen_address_for_test(0x2300, 0x6800, scan_left);
        assert_eq!(raster.terrain_blips, None);
        assert_eq!(raster.old_object_blip_words_cleared, 4);
        assert_eq!(
            raster.active_object_blips,
            vec![RedLabelScannerObjectBlip {
                object_address: active,
                erase_table_address: 0xB05D,
                screen_address: active_screen,
                color: 0x1234,
            }]
        );
        assert_eq!(
            raster.inactive_object_blips,
            vec![RedLabelScannerObjectBlip {
                object_address: inactive,
                erase_table_address: 0xB05F,
                screen_address: inactive_screen,
                color: 0xABCD,
            }]
        );
        assert_eq!(raster.setend, 0xB061);
        assert_eq!(
            raster.player_blip,
            RedLabelScannerPlayerBlip {
                erase_table_address: 0xB061,
                previous_screen_address: Some(0x4B20),
                screen_address: 0x530F,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0x3010..0x3018),
            Some(&[0, 0, 0, 0, 0, 0, 0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x4B20..0x4B23),
            Some(&[0, 0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x4A20..0x4A22),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xB05D..0xB063),
            Some(
                &[
                    (active_screen >> 8) as u8,
                    active_screen as u8,
                    (inactive_screen >> 8) as u8,
                    inactive_screen as u8,
                    0x53,
                    0x0F,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA097..0xA099),
            Some(&[0xB0, 0x61][..])
        );
        assert_eq!(
            machine.red_label_ram_range(active_screen..active_screen + 2),
            Some(&[0x12, 0x34][..])
        );
        assert_eq!(
            machine.red_label_ram_range(inactive_screen..inactive_screen + 2),
            Some(&[0xAB, 0xCD][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x530F..0x5312),
            Some(&[0x90, 0x99, 0x90][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x5210..0x5211),
            Some(&[0x09][..])
        );
    }

    fn seed_player_one_for_player_start(machine: &mut ArcadeMachine) {
        machine.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        machine.memory.write_byte(0xA08C, 1).expect("set PLRCNT");
        machine.memory.write_byte(0xA1C9, 3).expect("set PLAS");
        machine.memory.write_byte(0xA1CA, 1).expect("set PWAV");
        machine.memory.write_byte(0xA1CB, 3).expect("set PSBC");
        machine.memory.write_byte(0xA1CC, 10).expect("set PTARG");
    }

    fn seed_player_two_for_player_start(machine: &mut ArcadeMachine) {
        machine.memory.write_byte(0xA08B, 2).expect("set CURPLR");
        machine.memory.write_byte(0xA08C, 1).expect("set PLRCNT");
        machine.memory.write_byte(0xA206, 3).expect("set P2 PLAS");
        machine.memory.write_byte(0xA207, 1).expect("set P2 PWAV");
        machine.memory.write_byte(0xA208, 3).expect("set P2 PSBC");
        machine.memory.write_byte(0xA209, 10).expect("set P2 PTARG");
    }

    #[test]
    fn player_start_entry_resets_process_lists_and_creates_runtime_process() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PLSTRT").expect("PLSTRT address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLSTRT process")
            .process_address;
        assert_eq!(
            machine
                .step_red_label_process_scheduler()
                .expect("schedule PLSTRT")
                .expect("scheduled PLSTRT")
                .process_address,
            process
        );
        let extra_process = machine
            .red_label_make_process(
                red_label_routine_address("REV").expect("REV address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make regular process")
            .process_address;
        let coin_process = machine
            .red_label_make_process(
                red_label_routine_address("REV").expect("REV address"),
                RED_LABEL_COIN_PROCESS_TYPE,
            )
            .expect("make coin process")
            .process_address;
        for address in 0xA142..0xA162 {
            machine
                .memory
                .write_byte(address, 0)
                .expect("clear FISTAB byte");
        }
        for address in 0xA026..0xA036 {
            machine
                .memory
                .write_byte(address, 0xEE)
                .expect("dirty PCRAM byte");
        }

        let start = machine
            .red_label_start_player_start_current_process()
            .expect("PLSTRT entry");

        assert_eq!(
            start,
            RedLabelPlayerStart::RuntimeProcessCreated {
                process_address: process,
                status: 0x7F,
                killed_processes: vec![RedLabelKilledProcess {
                    killed_process_address: extra_process,
                    previous_link_address: coin_process,
                }],
                runtime_process: RedLabelCreatedProcess {
                    process_address: 0xAAC5,
                    routine_address: red_label_routine_address("PLSTR3").expect("PLSTR3 address"),
                    process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                    class: RedLabelProcessClass::Regular,
                },
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA065),
            Some(&[0xAA, 0xC5, 0xAA, 0xD4, 0xA0, 0x5F][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAC5..0xAACC),
            Some(&[0x00, 0x00, 0xD9, 0x50, 0x01, 0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x7F][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA036),
            Some(&CRTAB_BYTES[..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0A4..0xA0A6),
            Some(&[0xA1, 0x42][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09F..0xA0A1),
            Some(&[0xA1, 0x62][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0A8..0xA0AA),
            Some(&[0xA1, 0xA2][..])
        );
        assert!(
            machine
                .red_label_ram_range(0xA142..0xA162)
                .expect("FISTAB range")
                .iter()
                .any(|byte| *byte != 0),
            "PLSTRT INIT20 should refresh FISTAB before the process handoff"
        );
    }

    #[test]
    fn player_start_entry_waits_for_coin_counters_then_runs_pinit() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PLSTRT").expect("PLSTRT address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLSTRT process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule PLSTRT");
        machine.memory.write_byte(0xA07F, 1).expect("set LCCNT");

        let sleep = machine
            .red_label_start_player_start_current_process()
            .expect("PLSTRT coin wait");

        assert_eq!(
            sleep,
            RedLabelPlayerStart::CoinCounterSleeping {
                process_address: process,
                status: 0x7F,
                killed_processes: Vec::new(),
                wakeup_address: red_label_routine_address("PLST1A").expect("PLST1A address"),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xD9, 0x3A, 0x0F][..])
        );

        machine.memory.write_byte(0xA07F, 0).expect("clear LCCNT");
        let continued = machine
            .red_label_continue_player_start_after_coin_counters_current_process()
            .expect("PLST1A continue");

        assert_eq!(
            continued,
            RedLabelPlayerStart::RuntimeProcessCreated {
                process_address: process,
                status: 0x7F,
                killed_processes: Vec::new(),
                runtime_process: RedLabelCreatedProcess {
                    process_address: 0xAAC5,
                    routine_address: red_label_routine_address("PLSTR3").expect("PLSTR3 address"),
                    process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                    class: RedLabelProcessClass::Regular,
                },
            }
        );
    }

    #[test]
    fn player_runtime_start_initializes_ram_and_support_processes() {
        let mut machine = ArcadeMachine::new();
        seed_player_one_for_player_start(&mut machine);
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PLSTR3").expect("PLSTR3 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLSTR3 process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule PLSTR3");

        let start = machine
            .red_label_start_player_runtime_current_process()
            .expect("PLSTR3 runtime start");
        let RedLabelPlayerStart::RuntimeSleeping {
            process_address,
            runtime,
            support_processes,
            prompt_display_required,
            prompt,
            screen_clear: runtime_screen_clear,
            target_count,
            status,
            wakeup_address,
            sleep_time,
        } = start
        else {
            panic!("expected PLSTR3 runtime sleep");
        };
        let expected_runtime = RedLabelPlayerRuntimeInit {
            current_player: 1,
            player_address: 0xA1C2,
            screen_switch: None,
            wave: 1,
            wall_color: RED_LABEL_WALL_COLOR_TABLE[0],
            remaining_lasers: 2,
            altitude_table: expected_alinit(),
            terrain_tables: expected_bginit(),
            top_display: runtime.top_display.clone(),
        };
        assert_eq!(process_address, process);
        assert_eq!(runtime, expected_runtime);
        assert!(!prompt_display_required);
        assert_eq!(prompt, None);
        assert_eq!(runtime_screen_clear, Some(active_screen_clear()));
        assert_eq!(target_count, Some(10));
        assert_eq!(status, Some(0x05));
        assert_eq!(
            support_processes
                .iter()
                .map(|created| created.routine_address)
                .collect::<Vec<_>>(),
            vec![
                red_label_routine_address("SCPROC").expect("SCPROC address"),
                red_label_routine_address("COLR").expect("COLR address"),
                red_label_routine_address("FLPUP").expect("FLPUP address"),
                red_label_routine_address("THPROC").expect("THPROC address"),
                red_label_routine_address("CBOMB").expect("CBOMB address"),
                red_label_routine_address("TIECOL").expect("TIECOL address"),
            ]
        );
        assert_eq!(
            wakeup_address,
            red_label_routine_address("PLS1").expect("PLS1")
        );
        assert_eq!(sleep_time, 0x60);
        assert_eq!(
            machine.red_label_ram_range(0xA08D..0xA08F),
            Some(&[0xA1, 0xC2][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09B..0xA09D),
            Some(&[0xA1, 0x1A][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA036..0xA037), Some(&[7][..]));
        assert_eq!(
            machine.red_label_ram_range(0xB300..0xB308),
            Some(&[0xE0, 0xE2, 0xE2, 0xE2, 0xE2, 0xE2, 0xE2, 0xE2][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xB700..0xB709),
            Some(&[0xDE, 0x07, 0x70, 0xDE, 0x07, 0x70, 0xDE, 0x07, 0x70][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xBE20..0xBF50),
            Some(&[0; 0x130][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x05][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA1C9..0xA1CA),
            Some(&[0x02][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xDA, 0x32, 0x60][..])
        );
    }

    #[test]
    fn characterization_player_runtime_start_mutates_runtime_tables_lists_and_video() {
        let mut machine = ArcadeMachine::new();
        seed_player_one_for_player_start(&mut machine);
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PLSTR3").expect("PLSTR3 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLSTR3 process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule PLSTR3");
        machine
            .memory
            .write_byte(0x202A, 0xE7)
            .expect("seed active screen byte");

        let current_process = red_label_process_cell_snapshot(&machine, process);
        let first_support_process = red_label_process_cell_snapshot(&machine, 0xAAD4);
        let free_head =
            red_label_ram_snapshot(&machine, "PLSTR3 free process head", 0xA061..0xA063);
        let current_player =
            red_label_ram_snapshot(&machine, "PLSTR3 current player pointer", 0xA08D..0xA08F);
        let game_status = red_label_ram_snapshot(&machine, "PLSTR3 game status", 0xA0BA..0xA0BB);
        let altitude_head =
            red_label_ram_snapshot(&machine, "PLSTR3 altitude table head", 0xB300..0xB308);
        let terrain_head =
            red_label_ram_snapshot(&machine, "PLSTR3 terrain table head", 0xB700..0xB709);
        let active_screen_byte = red_label_video_ram_snapshot(
            &machine,
            "PLSTR3 active screen clear byte",
            0x202A..0x202B,
        );

        let start = machine
            .red_label_start_player_runtime_current_process()
            .expect("PLSTR3 runtime start");

        assert!(matches!(start, RedLabelPlayerStart::RuntimeSleeping { .. }));
        current_process.assert_current_changed(&machine);
        first_support_process.assert_current_changed(&machine);
        free_head.assert_current_changed(&machine);
        current_player.assert_current_changed_to(&machine, &[0xA1, 0xC2]);
        game_status.assert_current_changed_to(&machine, &[0x05]);
        altitude_head
            .assert_current_changed_to(&machine, &[0xE0, 0xE2, 0xE2, 0xE2, 0xE2, 0xE2, 0xE2, 0xE2]);
        terrain_head.assert_current_changed_to(
            &machine,
            &[0xDE, 0x07, 0x70, 0xDE, 0x07, 0x70, 0xDE, 0x07, 0x70],
        );
        active_screen_byte.assert_current_changed_to(&machine, &[0x00]);
    }

    #[test]
    fn screen_switch_player_one_sets_upright_irq_hook_and_restores_map() {
        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA036, 7).expect("seed MAPCR");
        machine.memory.hardware_map = 5;

        let screen_switch = machine
            .memory
            .screen_switch_player_one()
            .expect("P1SW screen switch");

        assert_eq!(
            screen_switch,
            RedLabelScreenSwitch {
                routine: RedLabelScreenSwitchRoutine::PlayerOne,
                pia3_input: 0,
                cocktail_detected: false,
                mode: RedLabelIrqMode::Normal,
                irq_hook_opcode: RED_LABEL_IRQ_JUMP_OPCODE,
                irq_hook_target: RED_LABEL_IRQ_ADDRESS,
                pia3_control: RED_LABEL_P1SW_PIA3_CONTROL,
                watchdog_value: RED_LABEL_NORMAL_WATCHDOG_DATA,
                map_before: 7,
                map_after: 7,
                hardware_map_before: 5,
                hardware_map_writes: vec![0, 7],
                hardware_map_after: 7,
                screen_clear: None,
                stick_history_reset: false,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA08F..0xA092),
            Some(&[0x7E, 0xDF, 0x17][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA036..0xA037), Some(&[7][..]));
        assert_eq!(machine.red_label_hardware_map(), 7);
    }

    #[test]
    fn screen_switch_player_two_follows_pia3_cocktail_gate() {
        for (pia3_input, mode, irq_target, pia3_control, watchdog_value) in [
            (
                0x00,
                RedLabelIrqMode::Normal,
                RED_LABEL_IRQ_ADDRESS,
                RED_LABEL_P1SW_PIA3_CONTROL,
                RED_LABEL_NORMAL_WATCHDOG_DATA,
            ),
            (
                RED_LABEL_PIA3_COCKTAIL_BIT,
                RedLabelIrqMode::Inverted,
                RED_LABEL_IRQB_ADDRESS,
                RED_LABEL_P2SW_PIA3_CONTROL,
                RED_LABEL_INVERTED_WATCHDOG_DATA,
            ),
        ] {
            let mut machine = ArcadeMachine::new();
            machine.memory.write_byte(0xA036, 4).expect("seed MAPCR");
            machine.memory.hardware_map = 6;

            let screen_switch = machine
                .memory
                .screen_switch_player_two(pia3_input)
                .expect("P2SW screen switch");

            assert_eq!(
                screen_switch.routine,
                RedLabelScreenSwitchRoutine::PlayerTwo
            );
            assert_eq!(screen_switch.pia3_input, pia3_input);
            assert_eq!(
                screen_switch.cocktail_detected,
                pia3_input & RED_LABEL_PIA3_COCKTAIL_BIT != 0
            );
            assert_eq!(screen_switch.mode, mode);
            assert_eq!(screen_switch.irq_hook_target, irq_target);
            assert_eq!(screen_switch.pia3_control, pia3_control);
            assert_eq!(screen_switch.watchdog_value, watchdog_value);
            assert_eq!(screen_switch.map_before, 4);
            assert_eq!(screen_switch.map_after, 4);
            assert_eq!(screen_switch.hardware_map_before, 6);
            assert_eq!(screen_switch.hardware_map_writes, vec![0, 0, 4]);
            assert_eq!(screen_switch.hardware_map_after, 4);
            assert_eq!(screen_switch.screen_clear, None);
            assert!(!screen_switch.stick_history_reset);
            assert_eq!(
                machine.red_label_ram_range(0xA08F..0xA092),
                Some(
                    &[
                        RED_LABEL_IRQ_JUMP_OPCODE,
                        (irq_target >> 8) as u8,
                        irq_target as u8
                    ][..]
                )
            );
            assert_eq!(machine.red_label_ram_range(0xA036..0xA037), Some(&[4][..]));
            assert_eq!(machine.red_label_hardware_map(), 4);
        }
    }

    #[test]
    fn player_runtime_cocktail_screen_switch_selects_current_player_irq_hook() {
        for (current_player, routine, mode, irq_target) in [
            (
                1,
                RedLabelScreenSwitchRoutine::PlayerOne,
                RedLabelIrqMode::Normal,
                RED_LABEL_IRQ_ADDRESS,
            ),
            (
                2,
                RedLabelScreenSwitchRoutine::PlayerTwo,
                RedLabelIrqMode::Inverted,
                RED_LABEL_IRQB_ADDRESS,
            ),
        ] {
            let mut machine = ArcadeMachine::new();
            if current_player == 1 {
                seed_player_one_for_player_start(&mut machine);
            } else {
                seed_player_two_for_player_start(&mut machine);
            }
            let process = machine
                .red_label_make_process(
                    red_label_routine_address("PLSTR3").expect("PLSTR3 address"),
                    RED_LABEL_SYSTEM_PROCESS_TYPE,
                )
                .expect("make PLSTR3 process")
                .process_address;
            machine
                .step_red_label_process_scheduler()
                .expect("schedule PLSTR3");

            let start = machine
                .memory
                .start_player_runtime_current_process_with_pia3(RED_LABEL_PIA3_COCKTAIL_BIT)
                .expect("cocktail PLSTR3 runtime start");

            let RedLabelPlayerStart::RuntimeSleeping {
                process_address,
                runtime,
                ..
            } = start
            else {
                panic!("expected PLSTR3 runtime sleep");
            };
            let screen_switch = runtime
                .screen_switch
                .expect("cocktail PLSTR3 should run screen switch");
            assert_eq!(process_address, process);
            assert_eq!(runtime.current_player, current_player);
            assert_eq!(screen_switch.routine, routine);
            assert_eq!(screen_switch.mode, mode);
            assert_eq!(screen_switch.irq_hook_target, irq_target);
            assert_eq!(screen_switch.screen_clear, Some(screen_clear()));
            assert!(screen_switch.stick_history_reset);
            assert_eq!(
                machine.red_label_ram_range(0xA08F..0xA092),
                Some(
                    &[
                        RED_LABEL_IRQ_JUMP_OPCODE,
                        (irq_target >> 8) as u8,
                        irq_target as u8
                    ][..]
                )
            );
            assert_eq!(
                machine.red_label_ram_range(0xA07B..0xA07D),
                Some(&[0xFF, 0xFF][..])
            );
            assert_eq!(machine.memory.live_irq_mode().expect("live IRQ mode"), mode);
        }
    }

    #[test]
