        machine
            .memory
            .write_word(object + 0x0A, 0x2000)
            .expect("set OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x6000)
            .expect("set OY16");
        machine
            .memory
            .write_word(object + 0x10, 0x0008)
            .expect("set OYV");

        let accelerated_y = sign_extend_u8_to_u16(0u8.wrapping_sub(0x08)).wrapping_add(0x0008);
        let expected_y_velocity = accelerated_y
            .wrapping_add(mini_swarmer_damping_adjustment(accelerated_y))
            .wrapping_add(sign_extend_u8_to_u16((0x8Fu8 & 0x1F).wrapping_sub(0x10)));

