    #[test]
    fn player_restore_runs_sczres_sczst_schizoid_branch() {
        let mut machine = ArcadeMachine::new();
        machine
            .red_label_make_process(
                red_label_routine_address("PLS1").expect("PLS1 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLS1 process");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule PLS1");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        machine.memory.write_byte(0xA1CC, 0).expect("clear PTARG");
        write_ram_bytes(&mut machine, 0xA1CD, &[0; 0x17]);
        machine
            .memory
            .write_byte(0xA1CD + 3, 1)
            .expect("seed SCZRES");
        machine
            .memory
            .write_byte(0xA1CD + 0x10, 0x1E)
            .expect("seed SZSTIM");
        machine.memory.write_byte(0xA0DF, 0).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0x4C).expect("set HSEED");
        machine.memory.write_byte(0xA0E1, 0).expect("set LSEED");
        machine.memory.write_word(0xA020, 0).expect("set BGL");

        let mut expected_rng = RandState {
            seed: 0,
            hseed: 0x4C,
            lseed: 0,
        };
        let phony_y16 = u16::from_be_bytes([
            expected_rng
                .seed
                .wrapping_shr(1)
                .wrapping_add(RED_LABEL_Y_MIN),
            0,
        ]);
        expected_rng.advance();
        let phony_x16 = u16::from_be_bytes([(expected_rng.seed & 0x3F).wrapping_add(0x80), 0x07]);
        expected_rng.advance();
        let placement_rng = expected_rng;
        let avoid_left = 0u16.wrapping_sub(300 * 32);
        let mut relative =
            u16::from_be_bytes([placement_rng.hseed, placement_rng.lseed]).wrapping_sub(avoid_left);
        if relative < 600 * 32 {
            relative = relative.wrapping_add(0x8000);
        }
        let x16 = relative.wrapping_add(avoid_left);
        let y16 = u16::from_be_bytes([
            placement_rng
                .seed
                .wrapping_shr(1)
                .wrapping_add(RED_LABEL_Y_MIN),
            0,
        ]);
        expected_rng.advance();
        let shot_timer = crate::red_label::rmax(0x1E, expected_rng.seed);

        let finish = machine
            .red_label_finish_player_start_current_process()
            .expect("PLS1 finish");
        let RedLabelPlayerStart::GameExecReady { restore, .. } = finish else {
            panic!("expected PLS1 game exec return");
        };
        let mini_swarmer_restore = restore.mini_swarmer_restore;
        assert_eq!(mini_swarmer_restore.reserve_count, 0);
        assert_eq!(mini_swarmer_restore.x_low_register, 0x07);
        assert_eq!(mini_swarmer_restore.batches.len(), 1);
        assert_eq!(mini_swarmer_restore.batches[0].phony_object_address, 0xA23C);
        assert_eq!(mini_swarmer_restore.batches[0].phony_x16, phony_x16);
        assert_eq!(mini_swarmer_restore.batches[0].phony_y16, phony_y16);
        assert!(!mini_swarmer_restore.batches[0].returned_phony_to_free_list);
        let schizoid_restore = restore.schizoid_restore.expect("schizoid restore branch");

        assert_eq!(schizoid_restore.reserve_count, 1);
        assert_eq!(schizoid_restore.active_count, 1);
        assert_eq!(schizoid_restore.created_objects.len(), 1);
        assert_eq!(restore.probe_restore, None);
        assert_eq!(restore.tie_restore, None);
        assert_eq!(machine.red_label_ram_range(0xA0FE..0xA0FF), Some(&[0][..]));
        assert_eq!(machine.red_label_ram_range(0xA115..0xA116), Some(&[1][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA0DF..0xA0E2),
            Some(&[expected_rng.seed, expected_rng.hseed, expected_rng.lseed][..])
        );

        let restored = &schizoid_restore.created_objects[0];
        assert_eq!(restored.object.object_address, 0xA253);
        assert_eq!(restored.object.process_address, 0xAAE3);
        assert_eq!(
            restored.object.descriptor.picture_address,
            red_label_object_picture_address("SCZP1").expect("SCZP1 address")
        );
        assert_eq!(
            restored.object.descriptor.collision_vector_address,
            red_label_routine_address("SCZKIL").expect("SCZKIL address")
        );
        assert_eq!(restored.object.descriptor.scanner_color, 0xCC33);
        assert_eq!(restored.x16, x16);
        assert_eq!(restored.y16, y16);
        assert_eq!(restored.xv, 0);
        assert_eq!(restored.yv, 0);
        assert_eq!(restored.discarded_pd_shot_timer, shot_timer);
        assert_eq!(
            restored.appearance,
            RedLabelAppearanceStart {
                object_address: 0xA253,
                original_picture_address: red_label_object_picture_address("SCZP1")
                    .expect("SCZP1 address"),
                final_picture_address: red_label_object_picture_address("SCZP1")
                    .expect("SCZP1 address"),
                relative_x: x16,
                slot_address: None,
                erased_previous_slot: false,
                sound_loaded: None,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAE5..0xAAEF),
            Some(&[0xF1, 0x5E, 0x01, 0x00, 0, 0xA2, 0x53, 0, 0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA253 + 0x02..0xA253 + 0x15),
            Some(
                &[
                    0xF8,
                    0xCE,
                    0,
                    0,
                    0xAA,
                    0xE3,
                    0xEF,
                    0x6D,
                    x16.to_be_bytes()[0],
                    x16.to_be_bytes()[1],
                    y16.to_be_bytes()[0],
                    y16.to_be_bytes()[1],
                    0,
                    0,
                    0,
                    0,
                    0xCC,
                    0x33,
                    0,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&[0xA2, 0x53][..])
        );
    }

    #[test]
    fn schizoid_process_close_offscreen_step_skips_hop_and_shot_timer() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SCZ0").expect("SCZ0 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make SCZ0 process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule SCZ0");
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("SCZP1")
                        .expect("SCZP1 address"),
                    collision_vector_address: red_label_routine_address("SCZKIL")
                        .expect("SCZKIL address"),
                    scanner_color: 0xCC33,
                },
            )
            .expect("init SCZ object")
            .object_address;
        machine
            .memory
            .write_word(process + 0x07, object)
            .expect("set process PD");
        machine
            .memory
            .write_byte(process + 0x09, 2)
            .expect("set process PD2");
        machine
            .memory
            .write_word(0xA0CC, 0x2100)
            .expect("set PLABX");
        machine.memory.write_byte(0xA0C0, 0x50).expect("set PLAYC");
        machine.memory.write_word(0xA108, 0x0100).expect("set SZYV");
        machine.memory.write_byte(0xA10A, 0x20).expect("set SZXV");
        machine
            .memory
            .write_word(object + 0x0A, 0x2000)
            .expect("set OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x6000)
            .expect("set OY16");

        let step = machine
            .red_label_step_schizoid_current_process()
            .expect("step SCZ0");

        assert_eq!(
            step,
            RedLabelSchizoidProcessStep {
                process_address: process,
                object_address: object,
                x_velocity: 0x0020,
                y_velocity: 0xFEFF,
                y_position: 0x60,
                shot_timer: 2,
                shot: None,
                wakeup_address: red_label_routine_address("SCZ0").expect("SCZ0 address"),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(object + 0x0E..object + 0x12),
            Some(&[0x00, 0x20, 0xFE, 0xFF][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x0A),
            Some(&[0xF1, 0x5E, 0x03, 0x00, 0x00, 0xA2, 0x3C, 0x02][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA099..0xA09A), Some(&[0][..]));
    }

    #[test]
    fn schizoid_process_due_shot_runs_shoot_and_loads_schizoid_sound() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SCZ0").expect("SCZ0 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make SCZ0 process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule SCZ0");
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("SCZP1")
                        .expect("SCZP1 address"),
                    collision_vector_address: red_label_routine_address("SCZKIL")
                        .expect("SCZKIL address"),
                    scanner_color: 0xCC33,
                },
            )
            .expect("init SCZ object")
            .object_address;
        machine
            .memory
            .write_word(process + 0x07, object)
            .expect("set process PD");
        machine
            .memory
            .write_byte(process + 0x09, 1)
            .expect("set process PD2");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine
            .memory
            .write_word(0xA0CC, 0x4000)
            .expect("set PLABX");
        machine.memory.write_byte(0xA0BF, 0x50).expect("set PLAXC");
        machine.memory.write_byte(0xA0C0, 0x70).expect("set PLAYC");
        write_ram_bytes(&mut machine, 0xA0DF, &[0x80, 0x00, 0x40]);
        machine.memory.write_byte(0xA107, 4).expect("set SZRY");
        machine.memory.write_word(0xA108, 0x0100).expect("set SZYV");
        machine.memory.write_byte(0xA10A, 0x20).expect("set SZXV");
        machine.memory.write_byte(0xA10B, 0x1E).expect("set SZSTIM");
        machine
            .memory
            .write_word(object + 0x0A, 0x2000)
            .expect("set OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x6000)
            .expect("set OY16");

        let mut expected_rng = RandState {
            seed: 0x80,
            hseed: 0x00,
            lseed: 0x40,
        };
        expected_rng.advance();
        let shot_timer = rmax(0x1E, expected_rng.seed);
        let expected_shell_x = 0x80;
        let expected_shell_y = 0x64;
        let expected_x_velocity = sign_extend_u8_to_u16(
            (expected_rng.seed & 0x1F)
                .wrapping_sub(0x10)
                .wrapping_add(0x50)
                .wrapping_sub(expected_shell_x),
        )
        .wrapping_shl(2);
        let expected_y_velocity = sign_extend_u8_to_u16(
            (expected_rng.lseed & 0x1F)
                .wrapping_sub(0x10)
                .wrapping_add(0x70)
                .wrapping_sub(expected_shell_y),
        )
        .wrapping_shl(2);

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("SCZ0").expect("SCZ0 address"),
            )
            .expect("dispatch SCZ0");
        let RedLabelProcessDispatch::Schizoid(step) = dispatch else {
            panic!("expected SCZ0 dispatch");
        };
        let shot = step.shot.expect("schizoid shot");

        assert_eq!(step.process_address, process);
        assert_eq!(step.object_address, object);
        assert_eq!(step.x_velocity, 0x0020);
        assert_eq!(step.y_velocity, 0);
        assert_eq!(step.y_position, expected_shell_y);
        assert_eq!(step.shot_timer, shot_timer);
        assert_eq!(
            step.wakeup_address,
            red_label_routine_address("SCZ0").unwrap()
        );
        assert_eq!(shot.shell.shell_address, 0xA253);
        assert_eq!(shot.shell.firing_object_address, object);
        assert_eq!(shot.shell.owner_address, process);
        assert_eq!(
            shot.shell.descriptor,
            RedLabelShellDescriptor {
                output_routine_address: red_label_routine_address("FBOUT").unwrap(),
                picture_address: red_label_object_picture_address("BMBP1").unwrap(),
                kill_routine_address: red_label_routine_address("BKIL").unwrap(),
            }
        );
        assert_eq!(shot.x_velocity, expected_x_velocity);
        assert_eq!(shot.y_velocity, expected_y_velocity);
        assert_eq!(
            shot.sound_loaded,
            Some(RedLabelLoadedSoundTable {
                address: 0xD52A,
                priority: 0xC0,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0DF..0xA0E2),
            Some(&[expected_rng.seed, expected_rng.hseed, expected_rng.lseed][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x0A),
            Some(&[0xF1, 0x5E, 0x03, 0x00, 0x00, 0xA2, 0x3C, shot_timer][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA099..0xA09A), Some(&[1][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x6A][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA06D..0xA06F),
            Some(&[0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA253 + 0x02..0xA253 + 0x17),
            Some(
                &[
                    0xF9,
                    0x5B,
                    expected_shell_x,
                    expected_shell_y,
                    process.to_be_bytes()[0],
                    process.to_be_bytes()[1],
                    0xE5,
                    0x1E,
                    expected_shell_x,
                    expected_shell_y,
                    expected_shell_y,
                    expected_shell_x,
                    expected_x_velocity.to_be_bytes()[0],
                    expected_x_velocity.to_be_bytes()[1],
                    expected_y_velocity.to_be_bytes()[0],
                    expected_y_velocity.to_be_bytes()[1],
                    0xE4,
                    0xD9,
                    0,
                    20,
                    20,
                ][..]
            )
        );
    }

    #[test]
    fn sczkil_collision_runs_kilp_score_explosion_and_sound_path() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SCZ0").expect("SCZ0 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make SCZ0 process")
            .process_address;
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("SCZP1")
                        .expect("SCZP1 address"),
                    collision_vector_address: red_label_routine_address("SCZKIL")
                        .expect("SCZKIL address"),
                    scanner_color: 0xCC33,
                },
            )
            .expect("init SCZ object")
            .object_address;
        machine
            .red_label_activate_object_cell(object)
            .expect("activate SCZ object");
        machine.memory.write_byte(0xA115, 1).expect("set SCZCNT");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine
            .memory
            .write_word(object + 0x04, 0x5060)
            .expect("set OBJX/OBJY");
        machine
            .memory
            .write_word(object + 0x0A, 0x2000)
            .expect("set OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x6000)
            .expect("set OY16");
        machine
            .memory
            .write_byte(0xA08B, 1)
            .expect("set current player");
        machine
            .memory
            .write_word(0xA08D, 0xA1C2)
            .expect("set current player record");

        let collision = machine
            .red_label_dispatch_object_collision_vector(object)
            .expect("dispatch SCZKIL");
        let RedLabelObjectCollision::EnemyKilled(kill) = collision else {
            panic!("expected SCZKIL enemy kill");
        };

        assert_eq!(machine.red_label_ram_range(0xA115..0xA116), Some(&[0][..]));
        assert_eq!(kill.object_address, object);
        assert_eq!(
            kill.killed_process,
            RedLabelKilledProcess {
                killed_process_address: process,
                previous_link_address: 0xA05F,
            }
        );
        assert_eq!(kill.previous_object_link_address, 0xA065);
        assert_eq!(
            kill.score,
            RedLabelScoreOutcome {
                player_number: 1,
                bonus_awarded: false,
                sound_loaded: None,
            }
        );
        assert_eq!(
            kill.explosion,
            RedLabelExplosionStart {
                object_address: object,
                picture_address: red_label_object_picture_address("SCZP1").unwrap(),
                relative_x: 0x2000,
                slot_address: Some(0x9C00),
                erased_previous_slot: false,
                top_left: Some(0x8060),
                center: Some(0x8264),
            }
        );
        assert_eq!(
            kill.sound_loaded,
            Some(RedLabelLoadedSoundTable {
                address: 0xD4F8,
                priority: 0xD0,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&[0xAA, 0xC5][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x3C][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x9C00..0x9C0A),
            Some(&[0x01, 0x00, 0xF8, 0xCE, 0x9C, 0x40, 0x82, 0x64, 0x80, 0x60][..])
        );
    }

    #[test]
    fn mutant_regression_fixture_covers_restore_movement_fire_and_kill() {
        let mut restore = ArcadeMachine::new();
        restore
            .red_label_make_process(
                red_label_routine_address("PLS1").expect("PLS1 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make DC-11.3 PLS1 process");
        restore
            .step_red_label_process_scheduler()
            .expect("schedule DC-11.3 PLS1");
        restore.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        restore.memory.write_byte(0xA1CC, 0).expect("clear PTARG");
        write_ram_bytes(&mut restore, 0xA1CD, &[0; 0x17]);
        restore
            .memory
            .write_byte(0xA1CD + 3, 1)
            .expect("seed SCZRES");
        restore
            .memory
            .write_byte(0xA1CD + 0x10, 0x1E)
            .expect("seed SZSTIM");
        restore
            .memory
            .write_byte(0xA0DF, 0)
            .expect("set restore SEED");
        restore
            .memory
            .write_byte(0xA0E0, 0x4C)
            .expect("set restore HSEED");
        restore
            .memory
            .write_byte(0xA0E1, 0)
            .expect("set restore LSEED");
        restore
            .memory
            .write_word(0xA020, 0)
            .expect("set restore BGL");
        let restore_active_count =
            red_label_ram_snapshot(&restore, "DC-11.3 SCZCNT", 0xA115..0xA116);
        let restore_active_head =
            red_label_ram_snapshot(&restore, "DC-11.3 active object head", 0xA065..0xA067);
        let restore_free_process =
            red_label_ram_snapshot(&restore, "DC-11.3 free process head", 0xA061..0xA063);
        let restore_free_object =
            red_label_ram_snapshot(&restore, "DC-11.3 free object head", 0xA067..0xA069);

        let finish = restore
            .red_label_finish_player_start_current_process()
            .expect("DC-11.3 PLS1 finish");
        let RedLabelPlayerStart::GameExecReady {
            restore: restored, ..
        } = finish
        else {
            panic!("expected DC-11.3 PLS1 game exec return");
        };
        let schizoid_restore = restored.schizoid_restore.expect("DC-11.3 SCZST");
        let restored_schizoid = &schizoid_restore.created_objects[0];

        assert_eq!(schizoid_restore.reserve_count, 1);
        assert_eq!(schizoid_restore.active_count, 1);
        assert_eq!(schizoid_restore.created_objects.len(), 1);
        assert_eq!(
            restored_schizoid.object.descriptor.picture_address,
            red_label_object_picture_address("SCZP1").expect("SCZP1 address")
        );
        assert_eq!(
            restored_schizoid.object.descriptor.collision_vector_address,
            red_label_routine_address("SCZKIL").expect("SCZKIL address")
        );
        assert_eq!(restored_schizoid.object.descriptor.scanner_color, 0xCC33);
        assert_eq!(restore.red_label_ram_range(0xA0FE..0xA0FF), Some(&[0][..]));
        restore_active_count.assert_current_changed_to(&restore, &[1]);
        restore_active_head.assert_current_changed_to(&restore, &[0xA2, 0x53]);
        restore_free_process.assert_current_changed(&restore);
        restore_free_object.assert_current_changed(&restore);

        let mut movement = ArcadeMachine::new();
        let movement_process = schedule_support_process(&mut movement, "SCZ0");
        let movement_object = movement
            .red_label_init_object_cell(
                movement_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("SCZP1")
                        .expect("SCZP1 address"),
                    collision_vector_address: red_label_routine_address("SCZKIL")
                        .expect("SCZKIL address"),
                    scanner_color: 0xCC33,
                },
            )
            .expect("init DC-11.3 moving SCZ object")
            .object_address;
        movement
            .memory
            .write_word(movement_process + 0x07, movement_object)
            .expect("set moving SCZ PD");
        movement
            .memory
            .write_byte(movement_process + 0x09, 2)
            .expect("set moving SCZ shot timer");
        movement
            .memory
            .write_word(0xA0CC, 0x4000)
            .expect("set moving PLABX");
        movement
            .memory
            .write_byte(0xA0C0, 0x64)
            .expect("set moving PLAYC");
        movement
            .memory
            .write_byte(0xA0DF, 0)
            .expect("set moving SEED");
        movement.memory.write_byte(0xA107, 4).expect("set SZRY");
        movement
            .memory
            .write_word(0xA108, 0x0100)
            .expect("set SZYV");
        movement.memory.write_byte(0xA10A, 0x20).expect("set SZXV");
        movement
            .memory
            .write_word(movement_object + 0x04, 0x5060)
            .expect("set moving object screen address");
        movement
            .memory
            .write_word(movement_object + 0x0A, 0x2000)
            .expect("set moving OX16");
        movement
            .memory
            .write_word(movement_object + 0x0C, 0x6000)
            .expect("set moving OY16");
        let movement_object_before = red_label_object_cell_snapshot(&movement, movement_object);
        let movement_process_before = red_label_process_cell_snapshot(&movement, movement_process);

        let movement_step = movement
            .red_label_step_schizoid_current_process()
            .expect("DC-11.3 SCZ0 movement");

        assert_eq!(movement_step.process_address, movement_process);
        assert_eq!(movement_step.object_address, movement_object);
        assert_eq!(movement_step.x_velocity, 0x0020);
        assert_eq!(movement_step.y_velocity, 0xFEFF);
        assert_eq!(movement_step.y_position, 0x5C);
        assert_eq!(movement_step.shot_timer, 1);
        assert_eq!(movement_step.shot, None);
        movement_object_before.assert_current_changed(&movement);
        movement_process_before.assert_current_changed(&movement);
        assert_eq!(
            movement.red_label_ram_range(movement_process + 0x02..movement_process + 0x0A),
            Some(&[0xF1, 0x5E, 0x03, 0x00, 0x00, 0xA2, 0x3C, 0x01][..])
        );

        let mut fire = ArcadeMachine::new();
        let fire_process = schedule_support_process(&mut fire, "SCZ0");
        let fire_object = fire
            .red_label_init_object_cell(
                fire_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("SCZP1")
                        .expect("SCZP1 address"),
                    collision_vector_address: red_label_routine_address("SCZKIL")
                        .expect("SCZKIL address"),
                    scanner_color: 0xCC33,
                },
            )
            .expect("init DC-11.3 firing SCZ object")
            .object_address;
        fire.red_label_activate_object_cell(fire_object)
            .expect("activate DC-11.3 firing SCZ object");
        fire.memory
            .write_word(fire_process + 0x07, fire_object)
            .expect("set firing SCZ PD");
        fire.memory
            .write_byte(fire_process + 0x09, 1)
            .expect("set firing SCZ shot timer");
        fire.memory.write_word(0xA020, 0).expect("set firing BGL");
        fire.memory
            .write_word(0xA0CC, 0x4000)
            .expect("set firing PLABX");
        fire.memory.write_byte(0xA0BF, 0x50).expect("set PLAXC");
        fire.memory.write_byte(0xA0C0, 0x70).expect("set PLAYC");
        fire.memory
            .write_byte(0xA08B, 1)
            .expect("set current player");
        fire.memory
            .write_word(0xA08D, 0xA1C2)
            .expect("set current player record");
        write_ram_bytes(&mut fire, 0xA0DF, &[0x80, 0x00, 0x40]);
        fire.memory.write_byte(0xA107, 4).expect("set firing SZRY");
        fire.memory
            .write_word(0xA108, 0x0100)
            .expect("set firing SZYV");
        fire.memory
            .write_byte(0xA10A, 0x20)
            .expect("set firing SZXV");
        fire.memory
            .write_byte(0xA10B, 0x1E)
            .expect("set firing SZSTIM");
        fire.memory.write_byte(0xA115, 1).expect("set SCZCNT");
        fire.memory
            .write_word(fire_object + 0x04, 0x5060)
            .expect("set firing object screen address");
        fire.memory
            .write_word(fire_object + 0x0A, 0x2000)
            .expect("set firing OX16");
        fire.memory
            .write_word(fire_object + 0x0C, 0x6000)
            .expect("set firing OY16");
        let fire_object_before = red_label_object_cell_snapshot(&fire, fire_object);
        let fire_process_before = red_label_process_cell_snapshot(&fire, fire_process);
        let fire_shell_before = red_label_object_cell_snapshot(&fire, 0xA253);
        let fire_shell_head = red_label_ram_snapshot(&fire, "DC-11.3 shell head", 0xA06D..0xA06F);
        let fire_shell_count = red_label_ram_snapshot(&fire, "DC-11.3 shell count", 0xA099..0xA09A);
        let fire_sound = red_label_ram_snapshot(&fire, "DC-11.3 shot sound", 0xA0B0..0xA0B5);
        let mut expected_rng = RandState {
            seed: 0x80,
            hseed: 0x00,
            lseed: 0x40,
        };
        expected_rng.advance();
        let expected_shot_timer = rmax(0x1E, expected_rng.seed);

        let fire_step = fire
            .red_label_step_schizoid_current_process()
            .expect("DC-11.3 SCZ0 fire");
        let shot = fire_step.shot.expect("DC-11.3 schizoid shot");

        assert_eq!(fire_step.process_address, fire_process);
        assert_eq!(fire_step.object_address, fire_object);
        assert_eq!(fire_step.shot_timer, expected_shot_timer);
        assert_eq!(shot.shell.shell_address, 0xA253);
        assert_eq!(
            shot.shell.descriptor.output_routine_address,
            red_label_routine_address("FBOUT").expect("FBOUT address")
        );
        assert_eq!(
            shot.shell.descriptor.kill_routine_address,
            red_label_routine_address("BKIL").expect("BKIL address")
        );
        assert_eq!(
            shot.sound_loaded,
            Some(RedLabelLoadedSoundTable {
                address: 0xD52A,
                priority: 0xC0,
            })
        );
        fire_object_before.assert_current_changed(&fire);
        fire_process_before.assert_current_changed(&fire);
        fire_shell_before.assert_current_changed(&fire);
        fire_shell_head.assert_current_changed_to(&fire, &[0xA2, 0x53]);
        fire_shell_count.assert_current_changed_to(&fire, &[1]);
        fire_sound.assert_current_changed_to(&fire, &[0xD5, 0x28, 0xC0, 0x01, 0x01]);

        let kill_score = red_label_ram_snapshot(&fire, "DC-11.3 mutant score", 0xA1C2..0xA1C6);
        let kill_count = red_label_ram_snapshot(&fire, "DC-11.3 kill SCZCNT", 0xA115..0xA116);
        let kill_object_before = red_label_object_cell_snapshot(&fire, fire_object);
        let kill_process_before = red_label_process_cell_snapshot(&fire, fire_process);
        let kill_sound = red_label_ram_snapshot(&fire, "DC-11.3 kill sound", 0xA0B0..0xA0B5);
        let kill_active_head =
            red_label_ram_snapshot(&fire, "DC-11.3 kill active head", 0xA065..0xA067);

        let collision = fire
            .red_label_dispatch_object_collision_vector(fire_object)
            .expect("DC-11.3 SCZKIL");
        let RedLabelObjectCollision::EnemyKilled(kill) = collision else {
            panic!("expected DC-11.3 SCZKIL enemy kill");
        };

        assert_eq!(kill.object_address, fire_object);
        assert_eq!(
            kill.sound_loaded,
            Some(RedLabelLoadedSoundTable {
                address: 0xD4F8,
                priority: 0xD0,
            })
        );
        assert_eq!(fire.snapshot().scores.player_one, 150);
        kill_score.assert_current_changed_to(&fire, &[0x00, 0x00, 0x01, 0x50]);
        kill_count.assert_current_changed_to(&fire, &[0]);
        kill_object_before.assert_current_changed(&fire);
        kill_process_before.assert_current_changed(&fire);
        kill_sound.assert_current_changed_to(&fire, &[0xD4, 0xF6, 0xD0, 0x01, 0x01]);
        kill_active_head.assert_current_changed_to(&fire, &[0, 0]);
    }

    #[test]
    fn ufost_starts_ufo_process_object_velocity_and_appearance() {
        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA0DF, 0x12).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0x34).expect("set HSEED");
        machine.memory.write_word(0xA020, 0x2000).expect("set BGL");
        machine
            .memory
            .write_word(0xA0CC, 0x0000)
            .expect("set PLABX");
        machine
            .memory
            .write_word(0xA0C7, 0x0000)
            .expect("set PLAXV");
        machine.memory.write_byte(0xA0C0, 0x30).expect("set PLAYC");
        machine
            .memory
            .write_word(0xA0CA, 0x0000)
            .expect("set PLAYV");

        let start = machine.red_label_start_ufo_process().expect("UFOST");

        assert_eq!(
            start,
            RedLabelUfoStart {
                process: RedLabelCreatedProcess {
                    process_address: 0xAAC5,
                    routine_address: red_label_routine_address("UFOLP").expect("UFOLP address"),
                    process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                    class: super::RedLabelProcessClass::Regular,
                },
                object: super::RedLabelCreatedObject {
                    object_address: 0xA23C,
                    process_address: 0xAAC5,
                    descriptor: RedLabelObjectDescriptor {
                        picture_address: red_label_object_picture_address("UFOP1")
                            .expect("UFOP1 address"),
                        collision_vector_address: red_label_routine_address("UFOKIL")
                            .expect("UFOKIL address"),
                        scanner_color: 0x3333,
                    },
                },
                x16: 0x3234,
                y16: 0x4400,
                shot_timer: 8,
                velocity: RedLabelUfoVelocityUpdate {
                    x_velocity: Some(0xFFC0),
                    y_velocity: Some(0xFF80),
                },
                appearance: RedLabelAppearanceStart {
                    object_address: 0xA23C,
                    original_picture_address: red_label_object_picture_address("UFOP1")
                        .expect("UFOP1 address"),
                    final_picture_address: red_label_object_picture_address("NULOB")
                        .expect("NULOB address"),
                    relative_x: 0x1234,
                    slot_address: Some(0x9C00),
                    erased_previous_slot: false,
                    sound_loaded: Some(RedLabelLoadedSoundTable {
                        address: 0xD4EE,
                        priority: 0xD0,
                    }),
                },
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA23E..0xA250),
            Some(
                &[
                    0xF8, 0xEC, 0x00, 0x00, 0xAA, 0xC5, 0xEB, 0x2B, 0x32, 0x34, 0x44, 0x00, 0xFF,
                    0xC0, 0xFF, 0x80, 0x33, 0x33,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&[0xA2, 0x3C][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAACC..0xAAD0),
            Some(&[0xA2, 0x3C, 0x08, 0x00][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA119..0xA11A), Some(&[0][..]));
    }

    #[test]
    fn translated_process_dispatch_runs_ufost_start() {
        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA0DF, 0x12).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0x34).expect("set HSEED");
        machine.memory.write_word(0xA020, 0x2000).expect("set BGL");
        machine
            .memory
            .write_word(0xA0CC, 0x0000)
            .expect("set PLABX");
        machine
            .memory
            .write_word(0xA0C7, 0x0000)
            .expect("set PLAXV");
        machine.memory.write_byte(0xA0C0, 0x30).expect("set PLAYC");
        machine
            .memory
            .write_word(0xA0CA, 0x0000)
            .expect("set PLAYV");

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("UFOST").expect("UFOST address"),
            )
            .expect("dispatch UFOST");
        let RedLabelProcessDispatch::UfoStarted(start) = dispatch else {
            panic!("expected UFO start dispatch");
        };

        assert_eq!(
            start.process,
            RedLabelCreatedProcess {
                process_address: 0xAAC5,
                routine_address: red_label_routine_address("UFOLP").expect("UFOLP address"),
                process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                class: super::RedLabelProcessClass::Regular,
            }
        );
        assert_eq!(start.object.object_address, 0xA23C);
        assert_eq!(start.object.process_address, 0xAAC5);
        assert_eq!(
            start.object.descriptor,
            RedLabelObjectDescriptor {
                picture_address: red_label_object_picture_address("UFOP1").expect("UFOP1 address"),
                collision_vector_address: red_label_routine_address("UFOKIL")
                    .expect("UFOKIL address"),
                scanner_color: 0x3333,
            }
        );
        assert_eq!(start.x16, 0x3234);
        assert_eq!(start.y16, 0x4400);
        assert_eq!(start.shot_timer, 8);
        assert_eq!(
            start.velocity,
            RedLabelUfoVelocityUpdate {
                x_velocity: Some(0xFFC0),
                y_velocity: Some(0xFF80),
            }
        );
        assert_eq!(start.appearance.slot_address, Some(0x9C00));
        assert_eq!(
            machine.red_label_ram_range(0xAACC..0xAAD0),
            Some(&[0xA2, 0x3C, 0x08, 0x00][..])
        );
    }

    #[test]
    fn ufolp_dispatch_fires_cycles_wraps_and_updates_velocity() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "UFOLP");
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("UFOP1")
                        .expect("UFOP1 address"),
                    collision_vector_address: red_label_routine_address("UFOKIL")
                        .expect("UFOKIL address"),
                    scanner_color: 0x3333,
                },
            )
            .expect("init UFO object")
            .object_address;
        machine
            .red_label_activate_object_cell(object)
            .expect("activate UFO object");
        machine
            .memory
            .write_word(process + 0x07, object)
            .expect("set process PD");
        machine
            .memory
            .write_byte(process + 0x09, 1)
            .expect("set UFO shot timer");
        machine
            .memory
            .write_word(
                object + 0x02,
                red_label_object_picture_address("UFOP3").expect("UFOP3 address"),
            )
            .expect("set UFOP3");
        machine
            .memory
            .write_word(object + 0x04, 0x4060)
            .expect("set screen address");
        machine
            .memory
            .write_word(object + 0x0A, 0x1000)
            .expect("set OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x6000)
            .expect("set OY16");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine
            .memory
            .write_word(0xA0CC, 0x4000)
            .expect("set PLABX");
        machine.memory.write_word(0xA0C7, 0).expect("set PLAXV");
        machine.memory.write_byte(0xA0C0, 0x80).expect("set PLAYC");
        machine.memory.write_word(0xA0CA, 0).expect("set PLAYV");
        machine.memory.write_byte(0xA110, 0x20).expect("set UFSTIM");
        machine.memory.write_byte(0xA111, 0).expect("set UFOSK");
        machine.memory.write_byte(0xA0DF, 0x90).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0x20).expect("set HSEED");
        machine.memory.write_byte(0xA0E1, 0x13).expect("set LSEED");
        let mut expected_rand = RandState {
            seed: 0x90,
            hseed: 0x20,
            lseed: 0x13,
        };
        expected_rand.advance();
        let expected_shot_timer = rmax(0x20, expected_rand.seed);

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("UFOLP").expect("UFOLP address"),
            )
            .expect("dispatch UFOLP");
        let RedLabelProcessDispatch::Ufo(step) = dispatch else {
            panic!("expected UFO dispatch");
        };

        assert_eq!(
            step,
            RedLabelUfoProcessStep {
                process_address: process,
                object_address: object,
                shot_timer: expected_shot_timer,
                shot: Some(super::RedLabelEnemyShot {
                    shell: super::RedLabelCreatedShell {
                        shell_address: 0xA253,
                        firing_object_address: object,
                        owner_address: process,
                        descriptor: RedLabelShellDescriptor {
                            output_routine_address: red_label_routine_address("FBOUT")
                                .expect("FBOUT address"),
                            picture_address: red_label_object_picture_address("BMBP1")
                                .expect("BMBP1 address"),
                            kill_routine_address: red_label_routine_address("BKIL")
                                .expect("BKIL address"),
                        },
                    },
                    x_velocity: step.shot.as_ref().expect("shot").x_velocity,
                    y_velocity: step.shot.as_ref().expect("shot").y_velocity,
                    sound_loaded: Some(RedLabelLoadedSoundTable {
                        address: 0xD52F,
                        priority: 0xC0,
                    }),
                }),
                picture_address: red_label_object_picture_address("UFOP1").expect("UFOP1 address"),
                velocity: Some(RedLabelUfoVelocityUpdate {
                    x_velocity: Some(0x0040),
                    y_velocity: Some(0x0080),
                }),
                wakeup_address: red_label_routine_address("UFOLP").expect("UFOLP address"),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(object + 0x02..object + 0x12),
            Some(
                &[
                    0xF9, 0xA3, 0x40, 0x60, 0xAA, 0xC5, 0xEB, 0x2B, 0x10, 0x00, 0x60, 0x00, 0x00,
                    0x40, 0x00, 0x80,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x0A),
            Some(
                &[
                    0xEA,
                    0xB4,
                    6,
                    RED_LABEL_SYSTEM_PROCESS_TYPE,
                    0,
                    object.to_be_bytes()[0],
                    object.to_be_bytes()[1],
                    expected_shot_timer,
                ][..]
            )
        );
        assert_eq!(machine.red_label_ram_range(0xA099..0xA09A), Some(&[1][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA0B0..0xA0B5),
            Some(&[0xD5, 0x2D, 0xC0, 0x01, 0x01][..])
        );
    }

    #[test]
    fn baiter_regression_fixture_covers_spawn_pursuit_firing_and_lifetime() {
        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA0DF, 0x12).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0x34).expect("set HSEED");
        machine.memory.write_byte(0xA0E1, 0x13).expect("set LSEED");
        machine.memory.write_word(0xA020, 0x2000).expect("set BGL");
        machine
            .memory
            .write_word(0xA0CC, 0x0000)
            .expect("set PLABX");
        machine.memory.write_word(0xA0C7, 0).expect("set PLAXV");
        machine.memory.write_byte(0xA0C0, 0x30).expect("set PLAYC");
        machine.memory.write_word(0xA0CA, 0).expect("set PLAYV");
        let free_process_head =
            red_label_ram_snapshot(&machine, "DC-11.1 free process head", 0xA061..0xA063);
        let free_object_head =
            red_label_ram_snapshot(&machine, "DC-11.1 free object head", 0xA067..0xA069);
        let active_object_head =
            red_label_ram_snapshot(&machine, "DC-11.1 active object head", 0xA065..0xA067);

        let start = machine
            .red_label_start_ufo_process()
            .expect("DC-11.1 UFOST");
        let process = start.process.process_address;
        let object = start.object.object_address;

        assert_eq!(
            start.process.routine_address,
            red_label_routine_address("UFOLP").expect("UFOLP address")
        );
        assert_eq!(
            start.object.descriptor.collision_vector_address,
            red_label_routine_address("UFOKIL").expect("UFOKIL address")
        );
        assert_eq!(start.shot_timer, 8);
        assert_eq!(
            start.velocity,
            RedLabelUfoVelocityUpdate {
                x_velocity: Some(0xFFC0),
                y_velocity: Some(0xFF80),
            }
        );
        free_process_head.assert_current_changed(&machine);
        free_object_head.assert_current_changed(&machine);
        active_object_head.assert_current_changed_to(
            &machine,
            &[object.to_be_bytes()[0], object.to_be_bytes()[1]],
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x07..process + 0x0A),
            Some(&[object.to_be_bytes()[0], object.to_be_bytes()[1], 8][..])
        );

        assert_eq!(
            machine
                .step_red_label_process_scheduler()
                .expect("schedule DC-11.1 UFOLP")
                .expect("scheduled DC-11.1 UFOLP")
                .process_address,
            process
        );
        machine
            .memory
            .write_byte(process + 0x09, 1)
            .expect("force UFO shot timer");
        machine
            .memory
            .write_word(
                object + 0x02,
                red_label_object_picture_address("UFOP3").expect("UFOP3 address"),
            )
            .expect("force UFO picture wrap");
        machine
            .memory
            .write_word(object + 0x04, 0x4060)
            .expect("set UFO screen address");
        machine
            .memory
            .write_word(object + 0x0A, 0x1000)
            .expect("set UFO OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x6000)
            .expect("set UFO OY16");
        machine
            .memory
            .write_word(object + 0x0E, 0)
            .expect("set pre-shot UFO OXV");
        machine.memory.write_word(0xA020, 0).expect("set shot BGL");
        machine
            .memory
            .write_word(0xA0CC, 0x4000)
            .expect("set player absolute X");
        machine
            .memory
            .write_byte(0xA0C0, 0x80)
            .expect("set player Y");
        machine.memory.write_byte(0xA110, 0x20).expect("set UFSTIM");
        machine.memory.write_byte(0xA111, 0).expect("set UFOSK");
        machine
            .memory
            .write_byte(0xA0DF, 0x90)
            .expect("set shot SEED");
        machine
            .memory
            .write_byte(0xA0E0, 0x20)
            .expect("set shot HSEED");
        machine
            .memory
            .write_byte(0xA0E1, 0x13)
            .expect("set shot LSEED");
        let object_before_loop = red_label_object_cell_snapshot(&machine, object);
        let process_before_loop = red_label_process_cell_snapshot(&machine, process);
        let shell_head =
            red_label_ram_snapshot(&machine, "DC-11.1 shell list head", 0xA06D..0xA06F);
        write_ram_bytes(&mut machine, 0xA0B0, &[0, 0, 0, 0, 0]);
        let sound_state = red_label_ram_snapshot(&machine, "DC-11.1 sound state", 0xA0B0..0xA0B5);
        let mut expected_rand = RandState {
            seed: 0x90,
            hseed: 0x20,
            lseed: 0x13,
        };
        expected_rand.advance();
        let expected_shot_timer = rmax(0x20, expected_rand.seed);

        let step = machine
            .red_label_step_ufo_current_process()
            .expect("DC-11.1 UFOLP");

        assert_eq!(step.process_address, process);
        assert_eq!(step.object_address, object);
        assert_eq!(step.shot_timer, expected_shot_timer);
        assert!(step.shot.is_some());
        assert_eq!(
            step.picture_address,
            red_label_object_picture_address("UFOP1").expect("UFOP1 address")
        );
        assert_eq!(
            step.velocity,
            Some(RedLabelUfoVelocityUpdate {
                x_velocity: Some(0x0040),
                y_velocity: Some(0x0080),
            })
        );
        object_before_loop.assert_current_changed(&machine);
        process_before_loop.assert_current_changed(&machine);
        shell_head.assert_current_changed_to(&machine, &[0xA2, 0x53]);
        sound_state.assert_current_changed_to(&machine, &[0xD5, 0x2D, 0xC0, 0x01, 0x01]);
        assert_eq!(
            machine.red_label_ram_range(object + 0x02..object + 0x12),
            Some(
                &[
                    0xF9, 0xA3, 0x40, 0x60, 0xAA, 0xC5, 0xEB, 0x2B, 0x10, 0x00, 0x60, 0x00, 0x00,
                    0x40, 0x00, 0x80,
                ][..]
            )
        );

        machine.memory.write_byte(0xA119, 1).expect("set UFOCNT");
        machine.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        let score_before_kill = red_label_ram_snapshot(&machine, "DC-11.1 score", 0xA1C2..0xA1C6);
        let process_before_kill = red_label_process_cell_snapshot(&machine, process);
        let object_before_kill = red_label_object_cell_snapshot(&machine, object);

        let collision = machine
            .red_label_dispatch_object_collision_vector(object)
            .expect("DC-11.1 UFOKIL");
        let RedLabelObjectCollision::UfoKilled(kill) = collision else {
            panic!("expected DC-11.1 UFOKIL collision");
        };

        assert_eq!(kill.object_address, object);
        assert_eq!(kill.killed_process.killed_process_address, process);
        assert_eq!(machine.red_label_ram_range(0xA119..0xA11A), Some(&[0][..]));
        score_before_kill.assert_current_changed_to(&machine, &[0x00, 0x00, 0x02, 0x00]);
        process_before_kill.assert_current_changed(&machine);
        object_before_kill.assert_current_changed(&machine);
        assert_eq!(machine.snapshot().scores.player_one, 200);
    }

    #[test]
    fn landst_starts_lander_process_object_and_target() {
        let mut machine = ArcadeMachine::new();
        let astro_process = machine
            .red_label_make_process(
                red_label_routine_address("ASTRO").expect("ASTRO address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make ASTRO process")
            .process_address;
        let astronaut = machine
            .red_label_init_object_cell(
                astro_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("ASTP1")
                        .expect("ASTP1 address"),
                    collision_vector_address: red_label_routine_address("ASTKIL")
                        .expect("ASTKIL address"),
                    scanner_color: 0x1111,
                },
            )
            .expect("init astronaut")
            .object_address;
        machine
            .red_label_activate_object_cell(astronaut)
            .expect("activate astronaut");
        machine
            .memory
            .write_word(0xA11C, astronaut)
            .expect("set TLIST");
        machine.memory.write_word(0xA09B, 0xA11A).expect("set TPTR");
        machine.memory.write_byte(0xA0FA, 1).expect("set ASTCNT");
        write_ram_bytes(&mut machine, 0xA0DF, &[0x00, 0x00, 0x10]);
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine.memory.write_byte(0xA102, 8).expect("set LNDXV");
        machine
            .memory
            .write_word(0xA103, 0x0100)
            .expect("set LNDYV");
        machine.memory.write_byte(0xA105, 0x20).expect("set LDSTIM");

        let mut expected_rng = RandState {
            seed: 0,
            hseed: 0,
            lseed: 0x10,
        };
        expected_rng.advance();
        let expected_x16 = u16::from_be_bytes([expected_rng.hseed, expected_rng.lseed]);
        expected_rng.advance();
        let expected_shot_timer = rmax(0x20, expected_rng.seed);
        expected_rng.advance();
        let expected_x_velocity_byte = rmax(8, expected_rng.seed);
        let expected_x_velocity = if expected_x_velocity_byte & 1 == 0 {
            u16::from(expected_x_velocity_byte)
        } else {
            !u16::from(expected_x_velocity_byte)
        };

        let start = machine.red_label_start_lander_processes(1).expect("LANDST");

        assert_eq!(start.requested_count, 1);
        assert!(start.schizoid_fallback.is_empty());
        assert_eq!(start.landers.len(), 1);
        let lander = &start.landers[0];
        assert_eq!(lander.process.process_address, 0xAAD4);
        assert_eq!(
            lander.process.routine_address,
            red_label_routine_address("LANDS0").expect("LANDS0 address")
        );
        assert_eq!(lander.object.object_address, 0xA253);
        assert_eq!(
            lander.object.descriptor,
            RedLabelObjectDescriptor {
                picture_address: red_label_object_picture_address("LNDP1").expect("LNDP1 address"),
                collision_vector_address: red_label_routine_address("LKILL")
                    .expect("LKILL address"),
                scanner_color: 0x4433,
            }
        );
        assert_eq!(lander.x16, expected_x16);
        assert_eq!(lander.y16.to_be_bytes()[0], RED_LABEL_Y_MIN + 2);
        assert_eq!(lander.y_velocity, 0x0100);
        assert_eq!(lander.shot_timer, expected_shot_timer);
        assert_eq!(lander.x_velocity, expected_x_velocity);
        assert_eq!(
            lander.target,
            Some(RedLabelLanderTarget {
                target_slot_address: 0xA11C,
                target_object_address: astronaut,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09B..0xA09D),
            Some(&[0xA1, 0x1C][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA112..0xA113), Some(&[1][..]));
        assert_eq!(
            machine.red_label_ram_range(
                lander.process.process_address + 0x07..lander.process.process_address + 0x0E
            ),
            Some(
                &[
                    lander.object.object_address.to_be_bytes()[0],
                    lander.object.object_address.to_be_bytes()[1],
                    astronaut.to_be_bytes()[0],
                    astronaut.to_be_bytes()[1],
                    0xA1,
                    0x1C,
                    expected_shot_timer,
                ][..]
            )
        );
    }

