    #[test]
    fn lands0_orbits_cycles_picture_and_fires_lander_shot() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "LANDS0");
        let lander = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("LNDP1")
                        .expect("LNDP1 address"),
                    collision_vector_address: red_label_routine_address("LKILL")
                        .expect("LKILL address"),
                    scanner_color: 0x4433,
                },
            )
            .expect("init lander")
            .object_address;
        let astronaut = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("ASTP1")
                        .expect("ASTP1 address"),
                    collision_vector_address: red_label_routine_address("ASTKIL")
                        .expect("ASTKIL address"),
                    scanner_color: 0x1111,
                },
            )
            .expect("init astronaut")
            .object_address;
        machine
            .red_label_activate_object_cell(lander)
            .expect("activate lander");
        machine
            .red_label_activate_object_cell(astronaut)
            .expect("activate astronaut");
        machine
            .memory
            .write_word(process + 0x07, lander)
            .expect("set PD");
        machine
            .memory
            .write_word(process + 0x09, astronaut)
            .expect("set PD2");
        machine
            .memory
            .write_word(process + 0x0B, 0xA11A)
            .expect("set PD4");
        machine
            .memory
            .write_byte(process + 0x0D, 1)
            .expect("set PD6");
        machine
            .memory
            .write_word(0xA11A, astronaut)
            .expect("set TLIST");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine.memory.write_byte(0xA0C0, 0x80).expect("set PLAYC");
        machine.memory.write_byte(0xA0C1, 0x40).expect("set PLAXC");
        machine.memory.write_word(0xA0C7, 0).expect("set PLAXV");
        write_ram_bytes(&mut machine, 0xA0DF, &[0x00, 0x00, 0x00]);
        machine
            .memory
            .write_word(0xA103, 0x0100)
            .expect("set LNDYV");
        machine.memory.write_byte(0xA105, 0x10).expect("set LDSTIM");
        machine
            .memory
            .write_word(lander + 0x0A, 0x2000)
            .expect("set lander X");
        machine
            .memory
            .write_word(lander + 0x0C, 0x5000)
            .expect("set lander Y");
        machine
            .memory
            .write_word(astronaut + 0x0A, 0x3000)
            .expect("set astronaut X");
        machine.memory.write_byte(0xB380, 0x90).expect("set ALTTBL");

        let mut expected_rng = RandState {
            seed: 0,
            hseed: 0,
            lseed: 0,
        };
        expected_rng.advance();
        let expected_shot_timer = rmax(0x10, expected_rng.seed);

        let step = machine
            .red_label_step_lander_orbit_current_process()
            .expect("LANDS0");
        let RedLabelLanderProcessStep::OrbitSleeping {
            process_address,
            object_address,
            target,
            altitude,
            y_velocity,
            shot_timer,
            shot,
            picture_address,
            wakeup_address,
        } = step
        else {
            panic!("expected LANDS0 orbit sleep");
        };
        let shot = shot.expect("lander shot");

        assert_eq!(process_address, process);
        assert_eq!(object_address, lander);
        assert_eq!(
            target,
            Some(RedLabelLanderTarget {
                target_slot_address: 0xA11A,
                target_object_address: astronaut,
            })
        );
        assert_eq!(altitude, 0x90);
        assert_eq!(y_velocity, 0x0100);
        assert_eq!(shot_timer, expected_shot_timer);
        assert_eq!(
            picture_address,
            red_label_object_picture_address("LNDP2").expect("LNDP2 address")
        );
        assert_eq!(
            wakeup_address,
            red_label_routine_address("LANDS0").expect("LANDS0 address")
        );
        assert_eq!(shot.shell.firing_object_address, lander);
        assert_eq!(shot.shell.owner_address, process);
        assert_eq!(
            shot.sound_loaded,
            Some(RedLabelLoadedSoundTable {
                address: 0xD525,
                priority: 0xC0,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xEF, 0xF6, 6][..])
        );
    }

    #[test]
