    #[test]
    fn player_death_after_explosion_runs_bonus_survivor_loop_when_wave_is_clear() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_player_death_process(&mut machine);
        machine.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        machine.memory.write_byte(0xA08C, 1).expect("set PLRCNT");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        machine.memory.write_byte(0xA0FA, 2).expect("set ASTCNT");
        machine.memory.write_byte(0xA1C9, 2).expect("set PLAS");
        machine.memory.write_byte(0xA1CA, 3).expect("set PWAV");
        machine
            .memory
            .write_byte(0x0029, 0xAB)
            .expect("set pre-active row");
        machine
            .memory
            .write_byte(0x002A, 0xAC)
            .expect("set active row");

        let death = machine
            .red_label_continue_player_death_after_explosion_current_process()
            .expect("PDTH5R");

        assert_eq!(
            death,
            RedLabelPlayerDeath::PostExplosionBonusAstronautSleeping {
                process_address: process,
                return_address: 0xDADB,
                screen_clear: Some(active_screen_clear()),
                text: Some(RedLabelBonusTextPlan {
                    attack_wave: RedLabelBonusTextCall {
                        vector_address: 0xC0F9,
                        screen_address: 0x3850,
                    },
                    wave_bcd: 0x03,
                    completed: RedLabelBonusTextCall {
                        vector_address: 0xC0FB,
                        screen_address: 0x3D60,
                    },
                    bonus_multiplier: RedLabelBonusTextCall {
                        vector_address: 0xC0F3,
                        screen_address: 0x3C90,
                    },
                    multiplier_bcd: 0x03,
                }),
                astronaut_counter: 2,
                astronaut: RedLabelPictureWrite {
                    screen_address: 0x3CA0,
                    picture_address: red_label_object_picture_address("ASTP3")
                        .expect("ASTP3 picture"),
                    width: 2,
                    height: 8,
                },
                next_astronaut_screen_address: 0x40A0,
                score_word: 0x0130,
                score: RedLabelScoreOutcome {
                    player_number: 1,
                    bonus_awarded: false,
                    sound_loaded: None,
                },
                wakeup_address: 0xDE66,
            }
        );
        assert_eq!(machine.red_label_ram_range(0xA0B3..0xA0B4), Some(&[0][..]));
        assert_eq!(machine.red_label_ram_range(0xA026..0xA027), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0x0029..0x002A),
            Some(&[0xAB][..])
        );
        assert_eq!(machine.red_label_ram_range(0x002A..0x002B), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA1C2..0xA1C6),
            Some(&[0x00, 0x00, 0x03, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3850..0x3858),
            Some(&[0x01, 0x01, 0x01, 0x01, 0x01, 0x01, 0x01, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3C50..0x3C58),
            Some(&[0x11, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x6550..0x6558),
            Some(&[0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x01, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x3D60..0x3D68),
            Some(&[0x01, 0x01, 0x01, 0x01, 0x01, 0x01, 0x01, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x5890..0x5898),
            Some(&[0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x01, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA050..0xA052),
            Some(&[0x5C, 0x90][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x07..process + 0x0F),
            Some(&[0x40, 0xA0, 0x02, 0x00, 0x00, 0x00, 0xDA, 0xDB][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xDE, 0x66, 0x04][..])
        );

        let second = machine
            .red_label_continue_player_death_bonus_astronaut_current_process()
            .expect("BC1 second survivor");
        let RedLabelPlayerDeath::PostExplosionBonusAstronautSleeping {
            astronaut_counter,
            astronaut,
            next_astronaut_screen_address,
            score_word,
            ..
        } = second
        else {
            panic!("expected second survivor sleep");
        };
        assert_eq!(astronaut_counter, 1);
        assert_eq!(astronaut.screen_address, 0x40A0);
        assert_eq!(next_astronaut_screen_address, 0x44A0);
        assert_eq!(score_word, 0x0130);
        assert_eq!(
            machine.red_label_ram_range(0xA1C2..0xA1C6),
            Some(&[0x00, 0x00, 0x06, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x07..process + 0x0A),
            Some(&[0x44, 0xA0, 0x01][..])
        );

        let wave_sleep = machine
            .red_label_continue_player_death_bonus_astronaut_current_process()
            .expect("BC1 wave advance");
        let RedLabelPlayerDeath::PostExplosionBonusWaveAdvanceSleeping {
            process_address,
            return_address,
            previous_astronaut_counter,
            wave,
            wakeup_address,
        } = wave_sleep
        else {
            panic!("expected bonus wave-advance sleep");
        };
        assert_eq!(process_address, process);
        assert_eq!(return_address, 0xDADB);
        assert_eq!(previous_astronaut_counter, 0);
        assert_eq!(wave.previous_wave, 3);
        assert_eq!(wave.wave, 4);
        assert_eq!(wakeup_address, 0xDE79);
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xDE, 0x79, 0x80][..])
        );

        machine
            .memory
            .write_byte(0x002A, 0xDD)
            .expect("dirty active row before BC3");
        let finished = machine
            .red_label_finish_player_death_bonus_current_process()
            .expect("BC3 return");
        assert_eq!(
            finished,
            RedLabelPlayerDeath::PostExplosionRespawnJump {
                process_address: process,
                next_player: 1,
                player_start_address: 0xD919,
            }
        );
        assert_eq!(machine.red_label_ram_range(0x002A..0x002B), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x04),
            Some(&[0xD9, 0x19][..])
        );
    }

    #[test]
    fn player_death_branch_fixture_covers_respawn_game_over_switch_and_wave_bonus() {
        let mut respawn = ArcadeMachine::new();
        let respawn_process = schedule_player_death_process(&mut respawn);
        respawn.memory.write_byte(0xA112, 1).expect("set LNDCNT");
        respawn.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        respawn.memory.write_byte(0xA08C, 1).expect("set PLRCNT");
        respawn.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        respawn.memory.write_byte(0xA1C9, 2).expect("set PLAS");

        let respawn_branch = respawn
            .red_label_continue_player_death_after_explosion_current_process()
            .expect("respawn PDTH5R");

        assert_eq!(
            respawn_branch,
            RedLabelPlayerDeath::PostExplosionRespawnJump {
                process_address: respawn_process,
                next_player: 1,
                player_start_address: 0xD919,
            }
        );
        assert_eq!(
            respawn.red_label_ram_range(respawn_process + 0x02..respawn_process + 0x04),
            Some(&[0xD9, 0x19][..])
        );

        let mut game_over = ArcadeMachine::new();
        let game_over_process = schedule_player_death_process(&mut game_over);
        game_over.memory.write_byte(0xA112, 1).expect("set LNDCNT");
        game_over.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        game_over.memory.write_byte(0xA08C, 1).expect("set PLRCNT");
        game_over
            .memory
            .write_word(0xA08D, 0xA1C2)
            .expect("set PLRX");
        game_over.memory.write_byte(0xA1C9, 0).expect("clear PLAS");

        let game_over_branch = game_over
            .red_label_continue_player_death_after_explosion_current_process()
            .expect("game-over PDTH5R");

        assert_eq!(
            game_over_branch,
            RedLabelPlayerDeath::GameOverSleeping {
                process_address: game_over_process,
                status: 0xFF,
                sound_command: SoundCommand::from_main_board_pia_port_b(0x2C),
                wakeup_address: 0xDB48,
            }
        );
        assert_eq!(
            game_over.red_label_ram_range(game_over_process + 0x02..game_over_process + 0x05),
            Some(&[0xDB, 0x48, 40][..])
        );

        let mut switch = ArcadeMachine::new();
        let switch_process = schedule_player_death_process(&mut switch);
        switch.memory.write_byte(0xA112, 1).expect("set LNDCNT");
        switch.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        switch.memory.write_byte(0xA08C, 2).expect("set PLRCNT");
        switch.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        switch
            .memory
            .write_byte(0xA1C9, 0)
            .expect("clear player one PLAS");
        switch
            .memory
            .write_byte(0xA206, 2)
            .expect("set player two PLAS");

        let switch_branch = switch
            .red_label_continue_player_death_after_explosion_current_process()
            .expect("switch-player PDTH5R");

        assert!(matches!(
            switch_branch,
            RedLabelPlayerDeath::PostExplosionSwitchPlayerSleeping {
                process_address,
                other_player: 2,
                wakeup_address: 0xDB15,
                ..
            } if process_address == switch_process
        ));
        assert_message_glyph_first_column(&switch, RED_LABEL_PLAYER_SWITCH_LABEL_SCREEN, 'P');
        assert_message_glyph_first_column(&switch, RED_LABEL_PLAYER_SWITCH_GAME_OVER_SCREEN, 'G');

        let mut wave = ArcadeMachine::new();
        let wave_process = schedule_player_death_process(&mut wave);
        wave.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        wave.memory.write_byte(0xA08C, 1).expect("set PLRCNT");
        wave.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        wave.memory.write_byte(0xA0FA, 1).expect("set ASTCNT");
        wave.memory.write_byte(0xA1C9, 2).expect("set PLAS");
        wave.memory.write_byte(0xA1CA, 3).expect("set PWAV");

        let bonus = wave
            .red_label_continue_player_death_after_explosion_current_process()
            .expect("wave-clear PDTH5R");
        assert!(matches!(
            bonus,
            RedLabelPlayerDeath::PostExplosionBonusAstronautSleeping {
                process_address,
                astronaut_counter: 1,
                score_word: 0x0130,
                wakeup_address: 0xDE66,
                ..
            } if process_address == wave_process
        ));

        let wave_sleep = wave
            .red_label_continue_player_death_bonus_astronaut_current_process()
            .expect("wave advance after last survivor");
        assert!(matches!(
            wave_sleep,
            RedLabelPlayerDeath::PostExplosionBonusWaveAdvanceSleeping {
                process_address,
                previous_astronaut_counter: 0,
                wave: RedLabelWaveParameters {
                    previous_wave: 3,
                    wave: 4,
                    ..
                },
                wakeup_address: 0xDE79,
                ..
            } if process_address == wave_process
        ));

        let restarted = wave
            .red_label_finish_player_death_bonus_current_process()
            .expect("BC3 return");
        assert_eq!(
            restarted,
            RedLabelPlayerDeath::PostExplosionRespawnJump {
                process_address: wave_process,
                next_player: 1,
                player_start_address: 0xD919,
            }
        );
    }

    #[test]
    fn reverse_entry_negates_direction_and_debounces_until_release() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_reverse_process(&mut machine, "REV");
        machine
            .memory
            .write_word(0xA0BD, 0x0300)
            .expect("set PLADIR");

        let started = machine
            .red_label_start_reverse_current_process()
            .expect("REV entry");

        assert_eq!(
            started,
            RedLabelReverse::StartedSleeping {
                process_address: process,
                previous_direction: 0x0300,
                new_direction: 0xFD00,
                wakeup_address: 0xE8AE,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0AF..0xA0B0),
            Some(&[0x01][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BB..0xA0BF),
            Some(&[0xFD, 0x00, 0x03, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE8, 0xAE, 0x02][..])
        );

        machine
            .memory
            .write_byte(0xA07B, 0x40)
            .expect("hold reverse");
        let pressed = machine
            .red_label_continue_reverse_current_process()
            .expect("REV2 held");
        assert_eq!(
            pressed,
            RedLabelReverse::PressedSleeping {
                process_address: process,
                wakeup_address: 0xE8AE,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE8, 0xAE, 0x02][..])
        );

        machine
            .memory
            .write_byte(0xA07B, 0x00)
            .expect("release reverse");
        let released = machine
            .red_label_continue_reverse_current_process()
            .expect("REV2 released");
        assert_eq!(
            released,
            RedLabelReverse::ReleaseSleeping {
                process_address: process,
                wakeup_address: 0xE8BC,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE8, 0xBC, 0x05][..])
        );

        let finished = machine
            .red_label_finish_reverse_current_process()
            .expect("REVX1");
        assert_eq!(
            finished,
            RedLabelReverse::Completed(RedLabelKilledProcess {
                killed_process_address: process,
                previous_link_address: 0xA05F,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0AF..0xA0B0),
            Some(&[0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&process.to_be_bytes()[..])
        );
    }

