    #[test]
    fn get_shell_cell_matches_getshl_allocation_and_field_setup() {
        let mut machine = ArcadeMachine::new();
        let owner = machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make owner process")
            .process_address;
        let source = machine
            .red_label_get_object_cell()
            .expect("get firing object cell");
        machine.memory.write_word(0xA020, 0x1000).expect("set BGL");
        machine
            .memory
            .write_word(source + 0x0A, 0x1100)
            .expect("set source OX16");
        machine
            .memory
            .write_word(source + 0x0C, 0x5001)
            .expect("set source OY16");
        let descriptor = RedLabelShellDescriptor {
            output_routine_address: 0x1111,
            picture_address: 0x2222,
            kill_routine_address: 0x3333,
        };

        let shell = machine
            .red_label_get_shell_cell(source, owner, descriptor)
            .expect("get shell")
            .expect("allocated shell");

        assert_eq!(shell.shell_address, 0xA253);
        assert_eq!(shell.firing_object_address, source);
        assert_eq!(shell.owner_address, owner);
        assert_eq!(shell.descriptor, descriptor);
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x6A][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA06D..0xA06F),
            Some(&[0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA099..0xA09A),
            Some(&[0x01][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA253..0xA26A),
            Some(
                &[
                    0x00, 0x00, 0x22, 0x22, 0x04, 0x50, 0xAA, 0xC5, 0x33, 0x33, 0x04, 0x50, 0x50,
                    0x04, 0x00, 0x00, 0x00, 0x00, 0x11, 0x11, 0x00, 0x14, 0x14,
                ][..]
            )
        );
    }

