    #[test]
    fn snapshot_reads_table_backed_red_label_state_instead_of_cached_scaffold_fields() {
        let mut machine = ArcadeMachine::new();
        let layout = red_label_ram_layout().expect("layout");
        let player_table = super::table_descriptor(&layout, "player").expect("player table");
        let player_two_address = super::table_entry_range(player_table, 1)
            .expect("player two range")
            .start;
        let ram_player = super::PlayerState {
            x: Fixed16(0x2468 << 8),
            y: Fixed16(0x1357 << 8),
            xv: Fixed16(0x0012_3400),
            yv: Fixed16(i32::from(-321i16) << 8),
            facing: Facing::Left,
            lives: 6,
            smart_bombs: 4,
        };
        let ram_rng = RandState {
            seed: 0x77,
            hseed: 0x88,
            lseed: 0x99,
        };

        machine.credits = 99;
        machine.current_player = 1;
        machine.wave = 1;
        machine.rng = RandState {
            seed: 0x01,
            hseed: 0x02,
            lseed: 0x03,
        };
        machine.player = super::PlayerState::default();
        machine.scores = super::ScoreState {
            player_one: 1,
            player_two: 2,
            high_score: 3,
            next_bonus: 321_000,
        };

        machine
            .memory
            .write_field_byte(&layout, "base_page", "CREDIT", 0x12)
            .expect("write credits");
        machine
            .memory
            .write_field_byte(&layout, "base_page", "CURPLR", 2)
            .expect("write current player");
        machine
            .memory
            .write_field_word(&layout, "base_page", "PLRX", player_two_address)
            .expect("write player pointer");
        machine
            .memory
            .write_player_score_value(&layout, 0, 123_456)
            .expect("write player one score");
        machine
            .memory
            .write_player_score_value(&layout, 1, 654_321)
            .expect("write player two score");
        machine
            .memory
            .write_player_runtime_snapshot(&layout, 1, ram_player, 9)
            .expect("write player two runtime");
        machine
            .memory
            .write_red_label_rand_state(&layout, ram_rng)
            .expect("write random state");

        let snapshot = machine.snapshot();

        assert_eq!(snapshot.credits, 12);
        assert_eq!(snapshot.current_player, 2);
        assert_eq!(snapshot.wave, 9);
        assert_eq!(
            snapshot.wave_profile,
            super::red_label_wave_table().profile_for_wave(9)
        );
        assert_eq!(snapshot.rng, ram_rng);
        assert_eq!(snapshot.player, ram_player);
        assert_eq!(snapshot.scores.player_one, 123_456);
        assert_eq!(snapshot.scores.player_two, 654_321);
        assert_eq!(
            snapshot.scores.high_score,
            machine
                .memory
                .all_time_high_score_value()
                .expect("high score")
        );
        assert_eq!(snapshot.scores.next_bonus, 321_000);
    }

    #[test]
    fn save_state_restore_round_trips_red_label_memory_and_trace_scheduler() {
        let mut machine = ArcadeMachine::new_cold_boot_trace();
        machine.memory.write_byte(0xA123, 0x5A).expect("seed RAM");
        machine.memory.cmos[0x7D] = 0xF1;
        machine.memory.palette_ram[5] = 0x5C;
        machine.memory.hardware_map = 7;
        machine.main_board_input_ports = DefenderInputPorts {
            in0: 0x02,
            in1: 0x40,
            in2: 0x08,
        };
        machine.main_board_watchdog_reset_count = 3;
        machine.main_board_video_counter_vpos = 0x00A8;
        machine.sound_board_last_command_latch =
            Some(SoundCommandLatch::from_main_board_pia_port_b(0x35));
        machine.sound_board_latch_write_count = 4;
        let saved_snapshot = machine.snapshot();
        let saved_board = machine.red_label_main_board_snapshot();
        let saved_sound = machine.red_label_sound_board_snapshot();
        let saved_cmos = red_label_cmos_snapshot(&machine, "save-state CMOS cell", 0x7D..0x7E);
        let saved_state = machine.save_state();

        machine.memory.write_byte(0xA123, 0xA5).expect("mutate RAM");
        machine.memory.cmos[0x7D] = 0xF0;
        machine.memory.palette_ram[5] = 0x00;
        machine.memory.hardware_map = 2;
        machine.main_board_input_ports = DefenderInputPorts::EMPTY;
        machine.main_board_watchdog_reset_count = 0;
        machine.main_board_video_counter_vpos = 0;
        machine.sound_board_last_command_latch = None;
        machine.sound_board_latch_write_count = 0;
        machine.trace_power_up_ram_fill = None;
        machine.frame = 99;
        machine.phase = GamePhase::Playing;
        machine.restore_state(saved_state);

        assert_eq!(machine.snapshot(), saved_snapshot);
        assert_eq!(
            machine.red_label_ram_range(0xA123..0xA124),
            Some(&[0x5A][..])
        );
        saved_cmos.assert_current_unchanged(&machine);
        assert_eq!(machine.red_label_palette_ram()[5], 0x5C);
        assert_eq!(machine.red_label_hardware_map(), 7);
        assert_eq!(machine.red_label_main_board_snapshot(), saved_board);
        assert_eq!(machine.red_label_sound_board_snapshot(), saved_sound);
        assert!(machine.trace_power_up_ram_fill.is_some());
    }

    #[test]
    fn step_updates_main_board_input_and_memory_surfaces() {
        let mut machine = ArcadeMachine::new_cold_boot_trace();
        machine.memory.write_byte(0x0001, 0x5A).expect("seed RAM");
        machine
            .memory
            .write_byte(0xA026, 0xD6)
            .expect("seed color map");
        let input = CabinetInput {
            coin: true,
            start_one: true,
            thrust: true,
            fire: true,
            ..CabinetInput::NONE
        };

        let output = machine.step(input);
        let board = machine.red_label_main_board_snapshot();

        assert_eq!(board.input_ports, input.defender_input_ports());
        assert_eq!(board.main_ram_crc32, crc32(machine.red_label_ram()));
        assert_eq!(board.cmos_crc32, crc32(machine.red_label_cmos_ram()));
        assert_eq!(board.palette_ram, *machine.red_label_palette_ram());
        assert_eq!(board.hardware_map, machine.red_label_hardware_map());
        assert_eq!(board.watchdog_reset_count, 0);
        assert_eq!(board.video_counter_vpos, 0);
        assert_eq!(board.video_counter_value, video_counter_read_value(0));
        assert_eq!(output.main_board, board);
        assert_eq!(output.sound_board, machine.red_label_sound_board_snapshot());
    }

    #[test]
    fn step_records_live_irq_watchdog_and_video_counter_surface() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        machine
            .memory
            .write_range(0xA08F..0xA092, &[0x7E, 0xDF, 0xC3])
            .expect("select IRQB hook");
        let palette_source = [
            0xA0, 0xA1, 0xA2, 0xA3, 0xB0, 0xB1, 0xB2, 0xB3, 0xB4, 0xB5, 0xC0, 0xC1, 0xC2, 0xC3,
            0xC4, 0xC5,
        ];
        machine
            .memory
            .write_range(0xA026..0xA036, &palette_source)
            .expect("seed PCRAM for live IRQ palette copy");
        let palette_before = *machine.red_label_palette_ram();

        let output = machine.step(CabinetInput::NONE);
        let board = machine.red_label_main_board_snapshot();

        assert_eq!(output.snapshot.phase, GamePhase::Playing);
        assert_eq!(output.main_board, board);
        assert_eq!(board.watchdog_reset_count, 1);
        assert_eq!(
            board.video_counter_vpos,
            u16::from(RED_LABEL_INVERTED_IRQ_PALETTE_COPY_LIMIT)
        );
        assert_eq!(
            board.video_counter_value,
            video_counter_read_value(board.video_counter_vpos)
        );
        assert_ne!(*machine.red_label_palette_ram(), palette_before);
        assert_eq!(machine.red_label_palette_ram(), &palette_source);
        assert_eq!(board.palette_ram, *machine.red_label_palette_ram());
    }

