    #[test]
    fn translated_start_sound_command_reaches_next_frame_output() {
        let mut machine = ArcadeMachine::new();
        insert_live_coin(&mut machine);
        step_until_sound_priority_clears(&mut machine);

        let start = machine.step(CabinetInput {
            start_one: true,
            ..CabinetInput::NONE
        });

        assert_eq!(start.sound_commands().collect::<Vec<_>>(), Vec::new());

        let next = machine.step(CabinetInput::NONE);

        assert_eq!(
            next.sound_commands().collect::<Vec<_>>(),
            vec![SoundCommand::from_main_board_pia_port_b(0x35)]
        );
    }

    #[test]
    fn live_thrust_sound_command_follows_previous_switch_scan() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);

        let thrust_pressed = machine.step(CabinetInput {
            thrust: true,
            ..CabinetInput::NONE
        });
        assert_eq!(
            thrust_pressed.sound_commands().collect::<Vec<_>>(),
            Vec::<SoundCommand>::new()
        );

        let thrust_held = machine.step(CabinetInput {
            thrust: true,
            ..CabinetInput::NONE
        });
        assert_eq!(
            thrust_held.sound_commands().collect::<Vec<_>>(),
            vec![SoundCommand::from_main_board_pia_port_b(0x29)]
        );

        let thrust_released = machine.step(CabinetInput::NONE);
        assert_eq!(
            thrust_released.sound_commands().collect::<Vec<_>>(),
            Vec::<SoundCommand>::new()
        );

        let after_release = machine.step(CabinetInput::NONE);
        assert_eq!(
            after_release.sound_commands().collect::<Vec<_>>(),
            vec![SoundCommand::from_main_board_pia_port_b(0x30)]
        );
    }

    #[test]
    fn xyzzy_overlay_hooks_are_explicit_and_disabled_until_enabled() {
        let disabled = super::CompatibilityState::default();
        for hook in super::XyzzyOverlayHook::ALL {
            assert!(
                !disabled.overlay_hook(hook),
                "{} should be disabled without xyzzy",
                hook.label()
            );
        }

        let active = super::CompatibilityState {
            xyzzy_active: true,
            xyzzy_invincible: false,
            xyzzy_auto_fire: false,
        };
        assert!(active.overlay_hook(super::XyzzyOverlayHook::UnlimitedSmartBombs));
        assert!(!active.overlay_hook(super::XyzzyOverlayHook::AutoFire));
        assert!(!active.overlay_hook(super::XyzzyOverlayHook::Invincibility));

        let toggled = super::CompatibilityState {
            xyzzy_active: true,
            xyzzy_invincible: true,
            xyzzy_auto_fire: true,
        };
        assert!(toggled.overlay_hook(super::XyzzyOverlayHook::AutoFire));
        assert!(toggled.overlay_hook(super::XyzzyOverlayHook::UnlimitedSmartBombs));
        assert!(toggled.overlay_hook(super::XyzzyOverlayHook::Invincibility));
        for hook in [
            super::XyzzyOverlayHook::ShotCapOverride,
            super::XyzzyOverlayHook::BulletMineClear,
            super::XyzzyOverlayHook::SafeHyperspace,
            super::XyzzyOverlayHook::CollisionDeathOverride,
            super::XyzzyOverlayHook::FallingHumanoidSurvival,
        ] {
            assert!(
                !toggled.overlay_hook(hook),
                "{} should stay explicit but inactive until implemented",
                hook.label()
            );
        }
    }

    #[test]
    fn xyzzy_auto_fire_hook_has_paired_arcade_and_overlay_behavior() {
        let mut arcade = ArcadeMachine::new();
        start_one_player_game_for_test(&mut arcade);
        arcade.set_compatibility(super::CompatibilityState {
            xyzzy_active: true,
            xyzzy_invincible: false,
            xyzzy_auto_fire: false,
        });

        let arcade_output = arcade.step(CabinetInput::NONE);
        assert!(
            !arcade_output
                .events()
                .any(|event| event == MachineEvent::FirePressed)
        );
        assert_eq!(
            arcade.red_label_main_board_snapshot().input_ports,
            DefenderInputPorts::EMPTY
        );

        let mut overlay = ArcadeMachine::new();
        start_one_player_game_for_test(&mut overlay);
        overlay.set_compatibility(super::CompatibilityState {
            xyzzy_active: true,
            xyzzy_invincible: false,
            xyzzy_auto_fire: true,
        });

        let overlay_output = overlay.step(CabinetInput::NONE);
        assert!(
            overlay_output
                .events()
                .any(|event| event == MachineEvent::FirePressed)
        );
        assert_eq!(
            overlay_output.snapshot.last_input_bits,
            CabinetInput::NONE.bits()
        );
        assert_eq!(
            overlay.red_label_main_board_snapshot().input_ports,
            DefenderInputPorts::EMPTY
        );
    }

    #[test]
    fn xyzzy_unlimited_smart_bomb_hook_has_paired_arcade_and_overlay_behavior() {
        let mut arcade = started_machine_with_empty_smart_bombs();
        let arcade_output = arcade.step(CabinetInput {
            smart_bomb: true,
            ..CabinetInput::NONE
        });
        assert!(
            !arcade_output
                .events()
                .any(|event| event == MachineEvent::SmartBombPressed)
        );
        assert_eq!(arcade_output.snapshot.player.smart_bombs, 0);
        assert_eq!(
            arcade.red_label_ram_range(0xA1CB..0xA1CC),
            Some(&[0x00][..])
        );

        let mut overlay = started_machine_with_empty_smart_bombs();
        overlay.set_compatibility(super::CompatibilityState {
            xyzzy_active: true,
            xyzzy_invincible: false,
            xyzzy_auto_fire: false,
        });
        let overlay_output = overlay.step(CabinetInput {
            smart_bomb: true,
            ..CabinetInput::NONE
        });
        assert!(
            overlay_output
                .events()
                .any(|event| event == MachineEvent::SmartBombPressed)
        );
        assert_eq!(overlay_output.snapshot.player.smart_bombs, 0);
        assert_eq!(
            overlay.red_label_ram_range(0xA1CB..0xA1CC),
            Some(&[0x00][..])
        );
    }

    #[test]
    fn xyzzy_invincibility_hook_is_trace_invisible_until_arcade_hook_exists() {
        let mut arcade = ArcadeMachine::new();
        start_one_player_game_for_test(&mut arcade);
        let arcade_output = arcade.step(CabinetInput::NONE);

        let mut overlay = ArcadeMachine::new();
        start_one_player_game_for_test(&mut overlay);
        overlay.set_compatibility(super::CompatibilityState {
            xyzzy_active: true,
            xyzzy_invincible: true,
            xyzzy_auto_fire: false,
        });
        let overlay_output = overlay.step(CabinetInput::NONE);

        assert!(overlay_output.snapshot.xyzzy_invincible);
        assert_eq!(
            TraceFrame::from_output(CabinetInput::NONE, &arcade_output),
            TraceFrame::from_output(CabinetInput::NONE, &overlay_output)
        );
        assert_eq!(
            arcade.red_label_main_board_snapshot(),
            overlay.red_label_main_board_snapshot()
        );
        assert_eq!(
            arcade.red_label_sound_board_snapshot(),
            overlay.red_label_sound_board_snapshot()
        );
    }

    #[test]
    fn xyzzy_disabled_empty_bombs_does_not_emit_overlay_smart_bomb() {
        let mut machine = started_machine_with_empty_smart_bombs();

        let output = machine.step(CabinetInput {
            smart_bomb: true,
            ..CabinetInput::NONE
        });
        let events = output.events().collect::<Vec<_>>();

        assert!(!events.contains(&MachineEvent::SmartBombPressed));
        assert_eq!(output.snapshot.player.smart_bombs, 0);
        assert_eq!(
            machine.red_label_ram_range(0xA1CB..0xA1CC),
            Some(&[0x00][..])
        );
    }

    #[test]
    fn xyzzy_auto_fire_and_unlimited_bombs_are_overlay_state() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        machine.player.smart_bombs = 0;
        machine
            .memory
            .write_byte(0xA1CB, 0)
            .expect("empty current player smart bombs");
        machine.set_compatibility(super::CompatibilityState {
            xyzzy_active: true,
            xyzzy_invincible: true,
            xyzzy_auto_fire: true,
        });

        let output = machine.step(CabinetInput {
            smart_bomb: true,
            ..CabinetInput::NONE
        });
        let events = output.events().collect::<Vec<_>>();

        assert!(events.contains(&MachineEvent::FirePressed));
        assert!(events.contains(&MachineEvent::SmartBombPressed));
        assert_eq!(output.snapshot.player.smart_bombs, 0);
        assert!(output.snapshot.xyzzy_invincible);
    }

    fn started_machine_with_empty_smart_bombs() -> ArcadeMachine {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        machine.player.smart_bombs = 0;
        machine
            .memory
            .write_byte(0xA1CB, 0)
            .expect("empty current player smart bombs");
        machine
    }
